@app.get("/api/public/inventory-csv")
async def get_inventory_csv():
    """Public endpoint — returns full product/service/bundle inventory as CSV text"""
    import csv, io
    from motor.motor_asyncio import AsyncIOMotorClient
    client = AsyncIOMotorClient(os.environ.get("MONGO_URL","mongodb://localhost:27017"))
    db_name = os.environ.get("DB_NAME","pet-os-live-test_database")
    db_pub = client[db_name]
    rows = []
    async for p in db_pub.products_master.find({},{"_id":0,"name":1,"pillar":1,"category":1,"sub_category":1,"price":1,"image_url":1,"description":1}):
        rows.append({"Type":"Product","Name":p.get("name",""),"Pillar":p.get("pillar",""),"Category":p.get("category",""),"SubCategory":p.get("sub_category",""),"Price":p.get("price",""),"HasImage":"Yes" if p.get("image_url") else "No","Description":(p.get("description","") or "")[:80]})
    async for s in db_pub.services_master.find({},{"_id":0,"name":1,"pillar":1,"category":1,"sub_category":1,"base_price":1,"price":1,"watercolor_image":1,"image_url":1,"description":1}):
        rows.append({"Type":"Service","Name":s.get("name",""),"Pillar":s.get("pillar",""),"Category":s.get("category",""),"SubCategory":s.get("sub_category",""),"Price":s.get("base_price") or s.get("price",""),"HasImage":"Yes" if (s.get("watercolor_image") or s.get("image_url")) else "No","Description":(s.get("description","") or "")[:80]})
    async for b in db_pub.care_bundles.find({},{"_id":0,"name":1,"pillar":1,"bundle_price":1,"image_url":1,"description":1,"items":1}):
        rows.append({"Type":"Bundle","Name":b.get("name",""),"Pillar":b.get("pillar",""),"Category":"Bundle","SubCategory":"","Price":b.get("bundle_price",""),"HasImage":"Yes" if b.get("image_url") else "No","Description":(b.get("description","") or "")[:80]})
    client.close()
    output = io.StringIO()
    writer = csv.DictWriter(output, fieldnames=["Type","Name","Pillar","Category","SubCategory","Price","HasImage","Description"])
    writer.writeheader()
    writer.writerows(rows)
    csv_content = output.getvalue()
    from fastapi.responses import Response
    return Response(content=csv_content, media_type="text/csv", headers={"Content-Disposition":"attachment; filename=tdc_inventory.csv","Access-Control-Allow-Origin":"*"})


@app.get("/api/public/system-overview")
async def get_system_overview():
    """Public endpoint — returns SYSTEM_OVERVIEW.md content"""
    import pathlib
    from fastapi.responses import Response
    md_path = pathlib.Path("/app/memory/SYSTEM_OVERVIEW.md")
    if md_path.exists():
        content = md_path.read_text(encoding="utf-8")
        return Response(content=content, media_type="text/plain", headers={"Access-Control-Allow-Origin":"*","Content-Disposition":"attachment; filename=SYSTEM_OVERVIEW.md"})
    return {"error": "File not found"}


@app.get("/api/public/docs-zip")
async def download_all_docs():
    """Public endpoint — returns ZIP of all 5 Claude context files + complete documentation"""
    import zipfile, io, pathlib
    from fastapi.responses import StreamingResponse
    
    files_to_zip = [
        ("/app/memory/SYSTEM_OVERVIEW.md", "SYSTEM_OVERVIEW.md"),
        ("/app/memory/ADMIN_GUIDE.md", "ADMIN_GUIDE.md"),
        ("/app/memory/MIRA_OS_ARCHITECTURE.md", "MIRA_OS_ARCHITECTURE.md"),
        ("/app/memory/PAGES_ARCHITECTURE.md", "PAGES_ARCHITECTURE.md"),
        ("/app/memory/PILLAR_ARCHITECTURE_STANDARD.md", "PILLAR_ARCHITECTURE_STANDARD.md"),
        ("/app/frontend/public/FOR_CLAUDE.txt", "FOR_CLAUDE.txt"),
        ("/app/frontend/public/complete-documentation.html", "complete-documentation.html"),
    ]
    
    buf = io.BytesIO()
    with zipfile.ZipFile(buf, "w", zipfile.ZIP_DEFLATED) as zf:
        for fpath, arcname in files_to_zip:
            p = pathlib.Path(fpath)
            if p.exists():
                zf.writestr(arcname, p.read_text(encoding="utf-8", errors="ignore"))
    buf.seek(0)
    return StreamingResponse(buf, media_type="application/zip",
        headers={"Content-Disposition": "attachment; filename=TDC_Claude_Context.zip",
                 "Access-Control-Allow-Origin": "*"})


@app.get("/api/admin/site-status")
async def get_site_status():
    """
    Get comprehensive site status report with real-time data.
    Returns counts, health status, and recent activity.
    """
    now = get_utc_timestamp()
    
    # Get counts from all major collections
    stats = {}
    try:
        # Core counts
        stats["products"] = await db.products_master.count_documents({})
        stats["services"] = await db.services_master.count_documents({})
        stats["members"] = await db.users.count_documents({})
        stats["orders"] = await db.orders.count_documents({})
        stats["pets"] = await db.pets.count_documents({})
        
        # Ticket counts by status
        stats["tickets_total"] = await db.service_desk_tickets.count_documents({})
        stats["tickets_open"] = await db.service_desk_tickets.count_documents({"status": {"$in": ["open", "new", "pending"]}})
        stats["tickets_blocked"] = await db.service_desk_tickets.count_documents({"status": "blocked"})
        stats["tickets_today"] = await db.service_desk_tickets.count_documents({
            "created_at": {"$gte": datetime.now(timezone.utc).replace(hour=0, minute=0, second=0).isoformat()}
        })
        
        # Content counts
        stats["blogs"] = await db.blogs.count_documents({})
        stats["faqs"] = await db.faqs.count_documents({})
        stats["collections"] = await db.enhanced_collections.count_documents({})
        
        # Party & Quotes
        stats["party_requests"] = await db.party_requests.count_documents({})
        stats["quotes"] = await db.quotes.count_documents({})
        stats["quotes_pending"] = await db.quotes.count_documents({"status": {"$in": ["sent", "viewed"]}})
        
        # Pillar counts
        stats["restaurants"] = await db.dine_restaurants.count_documents({}) if await db.list_collection_names().__contains__("dine_restaurants") else 0
        stats["stays"] = await db.stay_properties.count_documents({}) if "stay_properties" in await db.list_collection_names() else 0
        stats["trainers"] = await db.trainers.count_documents({}) if "trainers" in await db.list_collection_names() else 0
        
        # Recent activity (last 24 hours)
        yesterday = (datetime.now(timezone.utc) - timedelta(days=1)).isoformat()
        stats["orders_today"] = await db.orders.count_documents({"created_at": {"$gte": yesterday}})
        stats["new_members_today"] = await db.users.count_documents({"created_at": {"$gte": yesterday}})
        
    except Exception as e:
        logger.error(f"Error fetching site stats: {e}")
    
    # Determine pillar health status
    pillars = {
        "celebrate": {"status": "✅", "count": stats.get("party_requests", 0)},
        "dine": {"status": "✅", "count": stats.get("restaurants", 0)},
        "stay": {"status": "✅", "count": stats.get("stays", 0)},
        "shop": {"status": "✅", "count": stats.get("products", 0)},
        "services": {"status": "✅", "count": stats.get("services", 0)},
        "care": {"status": "✅", "count": await db.care_services.count_documents({}) if "care_services" in await db.list_collection_names() else 0},
        "learn": {"status": "✅", "count": stats.get("trainers", 0)},
    }
    
    # Features status
    features = {
        "working": [
            "Member Authentication & Dashboard",
            "Product Catalog & Cart",
            "Party Planning Wizard",
            "Quote Builder System",
            "Service Desk & Tickets",
            "Mira AI Concierge",
            "Pet Profiles & Pet Soul",
            "Notifications System",
            "Order Management",
            "Blog & FAQ CMS",
            "Admin Dashboard",
            "Mobile Responsive UI"
        ],
        "pending": [
            "WhatsApp Integration (awaiting approval)",
            "Razorpay Production Keys",
            "Membership Tiers Implementation",
            "Natural Language Search"
        ],
        "blocked": [
            "ElevenLabs TTS (awaiting key)",
            "Production Payment Gateway"
        ]
    }
    
    return {
        "status": "operational",
        "generated_at": now,
        "stats": stats,
        "pillars": pillars,
        "features": features,
        "summary": {
            "total_products": stats.get("products", 0),
            "total_services": stats.get("services", 0),
            "total_members": stats.get("members", 0),
            "open_tickets": stats.get("tickets_open", 0),
            "blocked_tickets": stats.get("tickets_blocked", 0),
            "pending_quotes": stats.get("quotes_pending", 0)
        }
    }


