@admin_router.post("/change-password")
async def change_password(
    current_password: str = Body(...),
    new_password: str = Body(...),
    username: str = Depends(verify_admin)
):
    """Change password (for logged-in admin) and send email notification"""
    global _admin_credentials_cache
    
    expected_password = _admin_credentials_cache.get("password") or ADMIN_PASSWORD
    
    if current_password != expected_password:
        raise HTTPException(status_code=401, detail="Current password is incorrect")
    
    if len(new_password) < 6:
        raise HTTPException(status_code=400, detail="New password must be at least 6 characters")
    
    # Update password
    await db.admin_config.update_one(
        {},
        {"$set": {
            "username": _admin_credentials_cache.get("username") or ADMIN_USERNAME,
            "password": new_password,
            "updated_at": get_utc_timestamp()
        }},
        upsert=True
    )
    
    # Update cache
    _admin_credentials_cache["password"] = new_password
    
    # Send notification email to admin
    try:
        change_time = datetime.now(timezone.utc).strftime("%d %B %Y at %H:%M UTC")
        html_content = f"""
        <!DOCTYPE html>
        <html>
        <head>
            <style>
                body {{ font-family: 'Segoe UI', sans-serif; background: #f8f4f0; margin: 0; padding: 20px; }}
                .container {{ max-width: 500px; margin: 0 auto; background: white; border-radius: 16px; overflow: hidden; box-shadow: 0 4px 20px rgba(0,0,0,0.1); }}
                .header {{ background: linear-gradient(135deg, #4caf50 0%, #2e7d32 100%); padding: 30px; text-align: center; }}
                .header h1 {{ color: white; margin: 0; font-size: 24px; }}
                .content {{ padding: 30px; text-align: center; }}
                .info-box {{ background: #e8f5e9; padding: 15px; border-radius: 8px; margin: 20px 0; }}
                .warning {{ background: #fff3e0; padding: 15px; border-radius: 8px; margin-top: 20px; font-size: 14px; color: #e65100; }}
                .footer {{ text-align: center; padding: 20px; background: #f8f4f0; color: #666; font-size: 12px; }}
            </style>
        </head>
        <body>
            <div class="container">
                <div class="header">
                    <h1>🔐 Password Changed</h1>
                </div>
                <div class="content">
                    <p>Hi Admin,</p>
                    <p>Your admin panel password was successfully changed.</p>
                    <div class="info-box">
                        <strong>Changed by:</strong> {username}<br>
                        <strong>Date:</strong> {change_time}
                    </div>
                    <div class="warning">
                        ⚠️ If you did not make this change, please contact support immediately and reset your password.
                    </div>
                </div>
                <div class="footer">
                    <p>The Doggy Company - Your Pet's Life Operating System</p>
                </div>
            </div>
        </body>
        </html>
        """
        
        resend.Emails.send({
            "from": SENDER_EMAIL,
            "to": ADMIN_EMAIL,
            "subject": "🔐 Admin Password Changed - The Doggy Company",
            "html": html_content
        })
        logger.info(f"Password change notification sent to {ADMIN_EMAIL}")
    except Exception as e:
        logger.error(f"Failed to send password change notification: {e}")
    
    logger.info("Admin password changed successfully")
    return {"success": True, "message": "Password changed successfully"}


@admin_router.post("/universal-seed")
async def universal_seed_endpoint():
    """
    UNIVERSAL PILLAR PROTOCOL - Seeds ALL 14 pillars with:
    - Products
    - Services
    - Unified Product Box
    - Pricing Tiers
    - Shipping Rules
    - HARDCODED Product Options (Base, Flavour, Size for cakes)
    - Engagement Data (Stories, Tips)
    - FAQs
    - Collections
    
    No auth required - designed to be called on deployment.
    """
    from scripts.universal_pillar_protocol import universal_seed
    from scripts.hardcode_product_options import hardcode_product_options
    from engagement_engine import initialize_engagement_data
    
    try:
        # Step 1: Run universal pillar seed
        results = await universal_seed(db)
        logger.info(f"Universal seed completed: {results}")
        
        # Step 2: ALWAYS hardcode product options (prevents options from disappearing)
        try:
            hardcode_results = await hardcode_product_options(db)
            results["hardcoded_options"] = hardcode_results
            logger.info(f"Hardcode product options completed: {hardcode_results}")
        except Exception as hc_error:
            logger.error(f"Hardcode product options failed (non-blocking): {hc_error}")
            results["hardcoded_options"] = {"error": str(hc_error)}
        
        # Step 3: Seed critical data (FAQs, Collections, Services)
        try:
            await auto_seed_critical_data()
            results["critical_data"] = "seeded"
            logger.info("Critical data seeded (FAQs, Collections, Services)")
        except Exception as cd_error:
            logger.error(f"Critical data seed failed (non-blocking): {cd_error}")
            results["critical_data"] = {"error": str(cd_error)}
        
        # Step 4: Seed engagement data (Stories, Tips)
        try:
            await initialize_engagement_data()
            stories_count = await db.transformation_stories.count_documents({})
            tips_count = await db.quick_win_tips.count_documents({})
            results["engagement"] = {"stories": stories_count, "tips": tips_count}
            logger.info(f"Engagement data seeded: {stories_count} stories, {tips_count} tips")
        except Exception as eng_error:
            logger.error(f"Engagement data seed failed (non-blocking): {eng_error}")
            results["engagement"] = {"error": str(eng_error)}
        
        return {
            "success": True,
            "message": "Universal seed complete (Products, Services, Options, FAQs, Stories, Tips)",
            "results": results
        }
    except Exception as e:
        logger.error(f"Universal seed failed: {e}")
        raise HTTPException(status_code=500, detail=str(e))


@admin_router.post("/hardcode-product-options")
async def hardcode_product_options_endpoint():
    """
    HARDCODE Product Options & Variants
    ====================================
    Permanently adds Base, Flavour, Size options and variants to cake products.
    This data is HARDCODED and will NOT be overwritten by Shopify sync.
    
    Products updated:
    - All cake products get Base + Flavour + Size options (96 variants each)
    - Treat products get Size options
    - Flavour products get Flavour options
    
    Run this after deployment or when options are missing.
    """
    from scripts.hardcode_product_options import hardcode_product_options
    
    try:
        results = await hardcode_product_options(db)
        logger.info(f"Hardcode product options completed: {results}")
        return {
            "success": True,
            "message": "Product options hardcoded successfully",
            "results": results
        }
    except Exception as e:
        logger.error(f"Hardcode product options failed: {e}")
        raise HTTPException(status_code=500, detail=str(e))


