@api_router.get("/categories/hierarchy")
async def get_category_hierarchy():
    """Get the full category hierarchy with product counts for shop navigation"""
    # Get hierarchy config from DB
    config = await db.config.find_one({"key": "category_hierarchy"}, {"_id": 0})
    hierarchy = config.get("hierarchy", {}) if config else {}
    
    # Add product counts for each parent category
    result = []
    for parent_id, parent_data in hierarchy.items():
        parent_count = await db.products_master.count_documents({"parent_category": parent_id})
        
        # Get subcategory counts
        subcategories = []
        for sub_id, sub_data in parent_data.get("subcategories", {}).items():
            db_cats = sub_data.get("db_categories", [])
            sub_count = 0
            for db_cat in db_cats:
                sub_count += await db.products_master.count_documents({"category": db_cat})
            
            subcategories.append({
                "id": sub_id,
                "name": sub_data.get("name"),
                "db_categories": db_cats,
                "count": sub_count
            })
        
        result.append({
            "id": parent_id,
            "name": parent_data.get("name"),
            "emoji": parent_data.get("emoji"),
            "pillar": parent_data.get("pillar"),
            "count": parent_count,
            "subcategories": subcategories
        })
    
    # Sort by count descending
    result.sort(key=lambda x: x["count"], reverse=True)
    
    return {"categories": result}


@api_router.get("/products")
async def get_public_products(
    category: Optional[str] = None, 
    parent_category: Optional[str] = None,
    collection: Optional[str] = None,
    pan_india: Optional[bool] = None,
    fresh_city: Optional[str] = None,
    availability: Optional[str] = None,  # 'fresh' or 'pan-india'
    search: Optional[str] = None,
    pillar: Optional[str] = None,
    breed: Optional[str] = None,  # Filter by breed
    shape: Optional[str] = None,  # NEW: Filter by cake shape (paw, bone, heart, etc.)
    page: int = 1,
    limit: int = 50,
    skip: int = 0  # Direct skip parameter for more control
):
    """Public endpoint for products - queries both products and unified_products collections"""
    query = {}
    
    # Handle parent_category filtering (new hierarchy system)
    if parent_category:
        query["parent_category"] = parent_category
    
    # Handle pillar-based filtering (for unified_products)
    # Now checks both 'pillar' field and 'pillars' array for multi-pillar products
    if pillar:
        query["$or"] = [
            {"pillar": pillar},
            {"pillars": pillar}
        ]
    
    # Handle category filtering (subcategory level)
    if category and category not in ["all", "pan-india"]:
        query["category"] = category
    
    # Handle fresh delivery city filter (for cakes)
    if fresh_city:
        city_lower = fresh_city.lower()
        query["$or"] = [
            {"fresh_delivery_cities": {"$regex": city_lower, "$options": "i"}},
            {"is_pan_india_shippable": True}  # Pan-India cakes available everywhere
        ]
    
    # Handle availability filter
    if availability == 'fresh':
        query["is_fresh_only"] = True
    elif availability == 'pan-india':
        query["is_pan_india_shippable"] = True
    
    # Handle collection-based filtering (e.g., valentine)
    if collection:
        coll = await db.collections.find_one(
            {"$or": [{"id": collection}, {"slug": collection}]},
            {"_id": 0, "product_ids": 1}
        )
        if coll and coll.get("product_ids"):
            query["id"] = {"$in": coll["product_ids"]}
    
    # Search logic
    if search:
        search_regex = {"$regex": search, "$options": "i"}
        search_query = {
            "$or": [
                {"name": search_regex},
                {"tags": search_regex},
                {"category": search_regex},
                {"description": search_regex},
                {"sizes.name": search_regex},
                {"flavors.name": search_regex}
            ]
        }
        if query:
            query = {"$and": [query, search_query]}
        else:
            query = search_query
    
    # Special handling for pan-india category
    if category == "pan-india" or pan_india:
        pan_india_query = {
            "$or": [
                {"category": "pan-india"},
                {"is_pan_india_shippable": True},
                {"category": {"$in": ["treats", "nut-butters", "desi-treats", "gift-cards"]}}
            ]
        }
        if query:
            query = {"$and": [query, pan_india_query]}
        else:
            query = pan_india_query
    elif category and not collection:
        # Search in category field, tags array, AND name (case-insensitive)
        # This allows subcategory pages like /fit/leashes to find products with "leash" in their name
        category_regex = {"$regex": f"^{category}$", "$options": "i"}
        category_contains = {"$regex": category, "$options": "i"}
        category_query = {
            "$or": [
                {"category": category_regex},
                {"tags": category_regex},
                {"name": category_contains},  # Also search in product name
                {"subcategory": category_regex}  # And subcategory field
            ]
        }
        if query:
            query = {"$and": [query, category_query]}
        else:
            query = category_query
    
    # Query from BOTH collections and merge results
    products = []
    seen_ids = set()
    
    # Add breed filter if specified
    if breed:
        breed_lower = breed.lower()
        breed_query = {
            "$or": [
                {"breed_tags": {"$regex": breed_lower, "$options": "i"}},
                {"tags": {"$regex": breed_lower, "$options": "i"}}
            ]
        }
        if query:
            query = {"$and": [query, breed_query]}
        else:
            query = breed_query
    
    # Add shape filter if specified (for cakes/bakery items)
    if shape:
        shape_lower = shape.lower()
        
        # Special handling for "round" - most cakes are round by default
        if shape_lower == "round":
            # For round shape, find cakes that DON'T have other specific shapes
            shape_query = {
                "$and": [
                    # Must be a cake/bakery item
                    {"$or": [
                        {"category": {"$regex": "cake|bakery", "$options": "i"}},
                        {"name": {"$regex": "cake|cupcake|pupcake", "$options": "i"}},
                        {"tags": {"$regex": "cake|bakery", "$options": "i"}}
                    ]},
                    # Should NOT have other specific shapes in name
                    {"name": {"$not": {"$regex": "paw|bone|heart|star|square|number|donut", "$options": "i"}}}
                ]
            }
        else:
            shape_query = {
                "$or": [
                    # Check the new structured field
                    {"pillars_occasions.cake_bakery.shape": shape_lower},
                    # Fallback to searching in name/tags
                    {"name": {"$regex": shape_lower, "$options": "i"}},
                    {"tags": {"$regex": shape_lower, "$options": "i"}},
                    {"shape": shape_lower}  # Legacy flat field
                ]
            }
        
        if query:
            query = {"$and": [query, shape_query]}
        else:
            query = shape_query
    
    # Add is_active filter - only show active products (or products without is_active field set, or is_active=null)
    active_filter = {"$or": [{"is_active": True}, {"is_active": {"$exists": False}}, {"is_active": None}]}
    if query:
        query = {"$and": [query, active_filter]}
    else:
        query = active_filter
    
    # Get total count first for pagination
    total_count = await db.products_master.count_documents(query if query else {})
    
    # Calculate skip for pagination (use direct skip if provided, otherwise calculate from page)
    actual_skip = skip if skip > 0 else (page - 1) * limit
    
    # First, query products_master collection with pagination
    # Sort by: 1) Has Cloudinary image (descending), 2) Created date (descending)
    old_products = await db.products_master.find(
        query, 
        {"_id": 0}
    ).sort([
        ("shopify_id", -1),  # Shopify-sourced products (real photos) first
        ("created_at", -1)  # Then by newest first
    ]).skip(actual_skip).limit(limit).to_list(limit)
    for p in old_products:
        pid = p.get("id") or p.get("shopify_id")
        if pid and pid not in seen_ids:
            seen_ids.add(pid)
            # Ensure title field exists
            if not p.get("title") and p.get("name"):
                p["title"] = p["name"]
            products.append(p)
    
    # Second, query unified_products collection with adapted query
    unified_query = {}
    
    # Apply parent_category filter if specified
    if parent_category:
        unified_query["parent_category"] = parent_category
    
    # Apply pillar filter if specified
    if pillar:
        unified_query["$or"] = [
            {"pillar": pillar},
            {"pillars": pillar}
        ]
    
    # Apply category filter if specified
    if category and category not in ["all", "pan-india"] and not collection:
        unified_query["category"] = category
    
    # Apply search filter
    if search:
        search_regex = {"$regex": search, "$options": "i"}
        search_filter = {
            "$or": [
                {"name": search_regex},
                {"tags": search_regex},
                {"category": search_regex},
                {"short_description": search_regex}
            ]
        }
        if unified_query:
            unified_query = {"$and": [unified_query, search_filter]}
        else:
            unified_query = search_filter
    
    # Only add visibility filter if we have other filters
    if unified_query:
        unified_query = {"$and": [unified_query, {"visibility.status": {"$in": ["active", None]}}]}
    else:
        unified_query = {"visibility.status": {"$in": ["active", None]}}
    
    # Add is_active filter to unified_products as well
    unified_active_filter = {"$or": [{"is_active": True}, {"is_active": {"$exists": False}}]}
    unified_query = {"$and": [unified_query, unified_active_filter]}
    
    # IMPORTANT: Exclude breed-specific "Soul Made" products from unified_products
    # These have breed names in their titles (e.g., "German Shepherd · Birthday Cake")
    # Soul Made products should ONLY be shown in their dedicated section via /api/mockups/breed-products
    breed_exclusion_pattern = r"^(Labrador|Golden Retriever|German Shepherd|Beagle|Bulldog|Poodle|Rottweiler|Yorkshire|Boxer|Dachshund|Siberian Husky|Husky|Doberman|Great Dane|Shih Tzu|Pug|Chihuahua|Pomeranian|Maltese|Cocker Spaniel|Border Collie|Cavalier|French Bulldog|Indie|Indian Pariah|American Bully|Chow Chow|Dalmatian|Jack Russell|Lhasa Apso|Italian Greyhound|Scottish Terrier|St Bernard|Schnoodle|Irish Setter)\s*[·:]"
    
    unified_query = {"$and": [
        unified_query,
        {"name": {"$not": {"$regex": breed_exclusion_pattern, "$options": "i"}}}
    ]}
    
    try:
        # Sort by created_at descending to show newest items first
        unified_products = await db.unified_products.find(unified_query, {"_id": 0}).sort("created_at", -1).to_list(500)
        for p in unified_products:
            pid = p.get("id") or p.get("shopify_id")
            if pid and pid not in seen_ids:
                seen_ids.add(pid)
                # Adapt unified product format to legacy format
                adapted = {
                    "id": p.get("id"),
                    "name": p.get("name"),
                    "title": p.get("name"),
                    "description": p.get("short_description") or p.get("long_description"),
                    "price": p.get("pricing", {}).get("base_price", 0),
                    "images": p.get("images", []),
                    "image": p.get("thumbnail") or (p.get("images", [None])[0] if p.get("images") else None),
                    "category": p.get("category"),
                    "tags": p.get("tags", []),
                    "in_stock": p.get("in_stock", True),
                    "pillars": p.get("pillars", []),
                    # Preserve other useful fields
                    "shopify_id": p.get("shopify_id"),
                    "sku": p.get("sku"),
                    "is_customizable": p.get("is_customizable", False),
                    # Include Pawmeter scores for seamless experience
                    "pawmeter": p.get("pawmeter"),
                }
                products.append(adapted)
    except Exception as e:
        logger.warning(f"Error querying unified_products: {e}")
    
    # Return with pagination info
    return {
        "products": products, 
        "total": total_count,
        "page": page,
        "limit": limit,
        "pages": (total_count + limit - 1) // limit,  # Total pages
        "has_more": skip + len(products) < total_count
    }


