# ==================== SERVICES API (Concierge® Services) ====================

@api_router.get("/services")
async def get_services(
    pillar: Optional[str] = None,
    category: Optional[str] = None,
    breed: Optional[str] = None,  # NEW: Filter by breed
    page: int = 1,  # NEW: Pagination
    limit: int = 50
):
    """Get Concierge® services - can filter by pillar"""
    query = {"is_active": {"$ne": False}}
    
    if pillar:
        query["pillar"] = pillar.lower()
    
    if category:
        query["category"] = category
    
    if breed:
        breed_lower = breed.lower()
        query["$or"] = [
            {"breed_tags": {"$regex": breed_lower, "$options": "i"}},
            {"tags": {"$regex": breed_lower, "$options": "i"}}
        ]
    
    # Try services_master first (main collection with 700+ services), fallback to services
    services_collection = db.services_master
    total_count = await services_collection.count_documents(query)
    
    # If services_master is empty, try services collection
    if total_count == 0:
        services_collection = db.services
        total_count = await services_collection.count_documents(query)
    
    # Calculate skip for pagination
    skip = (page - 1) * limit
    
    # Query with pagination
    services = await services_collection.find(
        query, 
        {"_id": 0}
    ).sort("created_at", -1).skip(skip).limit(limit).to_list(limit)
    
    return {
        "services": services, 
        "total": total_count,
        "page": page,
        "limit": limit,
        "pages": (total_count + limit - 1) // limit,
        "has_more": skip + len(services) < total_count
    }


