# ==================== SERVICE REQUESTS (CONCIERGE / ASK FORMS) ====================
class ServiceRequestPayload(BaseModel):
    type: str  # celebration_concierge, travel_request, etc.
    pillar: str
    source: Optional[str] = "web_form"
    customer: Dict[str, Any]
    details: Dict[str, Any]
    priority: Optional[str] = "normal"
    intent: Optional[str] = None

@api_router.post("/service-requests")
async def create_service_request(payload: ServiceRequestPayload):
    """
    Generic service request endpoint - for Ask Concierge forms, help requests, etc.
    Routes to unified flow: Notification → Service Desk → Unified Inbox
    """
    # Generate IDs
    request_id = f"REQ-{datetime.now().strftime('%Y%m%d')}-{uuid.uuid4().hex[:4].upper()}"
    ticket_id = f"TKT-{uuid.uuid4().hex[:8].upper()}"
    notification_id = f"NOTIF-{uuid.uuid4().hex[:8].upper()}"
    inbox_id = f"INBOX-{uuid.uuid4().hex[:8].upper()}"
    now = get_utc_timestamp()
    
    customer_name = payload.customer.get("name", "Customer")
    customer_email = payload.customer.get("email")
    customer_phone = payload.customer.get("phone")
    
    # Build HUMAN-FRIENDLY description from details
    def format_value(v):
        """Format a value for human reading"""
        if isinstance(v, dict):
            return None  # Skip nested dicts
        if isinstance(v, list):
            return ", ".join(str(x) for x in v) if v else None
        if isinstance(v, bool):
            return "Yes" if v else "No"
        return str(v) if v else None
    
    # Extract key details for member-friendly message
    pet_name = payload.details.get("pet_name", "your pet")
    service_type = payload.details.get("service_type", payload.type).replace("_", " ").title()
    services_requested = payload.details.get("services_requested", [])
    if isinstance(services_requested, list):
        services_str = ", ".join(s.replace("_", " ").title() for s in services_requested)
    else:
        services_str = str(services_requested).replace("_", " ").title()
    
    # Create a friendly description for the member
    member_friendly_description = f"""Hi {customer_name}! 👋

Your {service_type} request for {pet_name} has been received.

**Services:** {services_str if services_str else service_type}

Our Concierge® team will review your request and get back to you shortly with options tailored for {pet_name}.

Thank you for choosing The Doggy Company! 🐾"""

    # Create detailed description for admin/internal use
    details_items = []
    for k, v in payload.details.items():
        formatted = format_value(v)
        if formatted and k not in ['metadata', 'comfort_notes', 'behavior_flags', 'logistics']:
            details_items.append(f"- {k.replace('_', ' ').title()}: {formatted}")
    details_text = "\n".join(details_items)
    
    admin_description = f"""Service Request: {payload.type.replace('_', ' ').title()}
Pillar: {payload.pillar.title()}
Pet: {pet_name}
Services: {services_str}

Customer: {customer_name} ({customer_email or 'No email'})

Details:
{details_text}
"""
    
    # Determine priority and urgency
    priority = payload.priority or "normal"
    urgency = "high" if priority == "high" else ("medium" if priority == "normal" else "low")
    
    # ==================== STEP 1: NOTIFICATION ====================
    await db.admin_notifications.insert_one({
        "id": notification_id,
        "type": payload.type,
        "pillar": payload.pillar,
        "title": f"New {payload.type.replace('_', ' ').title()} Request",
        "message": f"{customer_name} submitted a {payload.pillar} request",
        "read": False,
        "status": "unread",
        "urgency": urgency,
        "request_id": request_id,
        "ticket_id": ticket_id,
        "inbox_id": inbox_id,
        "customer": {"name": customer_name, "email": customer_email, "phone": customer_phone},
        "details": payload.details,
        "link": f"/admin?tab=servicedesk&ticket={ticket_id}",
        "created_at": now,
        "read_at": None
    })
    logger.info(f"[SERVICE REQUEST] Notification created: {notification_id}")
    
    # ==================== STEP 2: SERVICE DESK TICKET ====================
    ticket = {
        "id": ticket_id,
        "ticket_id": ticket_id,
        "request_id": request_id,
        "notification_id": notification_id,
        "inbox_id": inbox_id,
        "type": payload.type,
        "category": payload.pillar,
        "subject": f"{service_type} - {pet_name} ({customer_name})",
        "description": admin_description,
        "status": "open",
        "priority": priority,
        "channel": payload.source or "web",
        "pillar": payload.pillar,
        "customer_name": customer_name,
        "customer_email": customer_email,
        "customer_phone": customer_phone,
        "pet_name": pet_name,
        "services_requested": services_str,
        "details": payload.details,
        "intent": payload.intent,
        "created_at": now,
        "updated_at": now,
        "assigned_to": None,
        "notes": [],
        "activity_log": [
            {"action": "created", "timestamp": now, "details": f"Request submitted via {payload.source}"}
        ]
    }
    await db.service_desk_tickets.insert_one(ticket)
    logger.info(f"[SERVICE REQUEST] Ticket created: {ticket_id}")
    
    # ==================== STEP 3: UNIFIED INBOX ====================
    await db.unified_inbox.insert_one({
        "id": inbox_id,
        "thread_id": inbox_id,
        "ticket_id": ticket_id,
        "request_id": request_id,
        "notification_id": notification_id,
        "pillar": payload.pillar,
        "type": "service_request",
        "channel": payload.source or "web",
        "customer_name": customer_name,
        "customer_email": customer_email,
        "customer_phone": customer_phone,
        "subject": f"{service_type} for {pet_name}",
        "preview": f"Your {service_type.lower()} request has been received. Our team will get back to you shortly.",
        "status": "open",
        "priority": priority,
        "created_at": now,
        "updated_at": now,
        "messages": [
            {
                "id": f"msg-{uuid.uuid4().hex[:8]}",
                "from": "system",
                "sender_name": "Mira Concierge",
                "content": member_friendly_description,
                "timestamp": now
            }
        ],
        "metadata": {
            "source": payload.source,
            "intent": payload.intent,
            "pillar": payload.pillar,
            "pet_name": pet_name,
            "services": services_str,
            "details": payload.details
        }
    })
    logger.info(f"[SERVICE REQUEST] Inbox entry created: {inbox_id}")
    
    # Store in service_requests collection for tracking
    await db.service_requests.insert_one({
        "id": request_id,
        "request_id": request_id,
        "ticket_id": ticket_id,
        "notification_id": notification_id,
        "inbox_id": inbox_id,
        "type": payload.type,
        "pillar": payload.pillar,
        "source": payload.source,
        "customer": payload.customer,
        "details": payload.details,
        "priority": priority,
        "intent": payload.intent,
        "status": "pending",
        "created_at": now,
        "updated_at": now
    })
    
    # ==================== STEP 4: MEMBER NOTIFICATION ====================
    # Create notification for the member so they can see it in their dashboard
    if customer_email:
        member_notif_id = f"MNOTIF-{uuid.uuid4().hex[:8].upper()}"
        await db.member_notifications.insert_one({
            "id": member_notif_id,
            "user_email": customer_email,
            "type": "service_request_received",
            "title": f"Request Received: {payload.type.replace('_', ' ').title()}",
            "message": f"Your {payload.type.replace('_', ' ')} request has been submitted. Our team will contact you shortly!",
            "ticket_id": ticket_id,
            "request_id": request_id,
            "pillar": payload.pillar,
            "link": "/dashboard?tab=requests",
            "read": False,
            "created_at": now,
            "timestamp": now
        })
        logger.info(f"[SERVICE REQUEST] Member notification created: {member_notif_id}")
    
    # ==================== STEP 5: PILLAR REQUEST ====================
    await db.pillar_requests.insert_one({
        "id": f"PR-{uuid.uuid4().hex[:8].upper()}",
        "ticket_id": ticket_id,
        "request_id": request_id,
        "pillar": payload.pillar,
        "type": payload.type,
        "user_email": customer_email,
        "customer_name": customer_name,
        "status": "pending",
        "details": payload.details,
        "created_at": now
    })
    logger.info(f"[SERVICE REQUEST] Pillar request created for {payload.pillar}")
    
    # ==================== STEP 6: CHANNEL INTAKES ====================
    # Track the source channel for unified inbox and analytics
    channel_intake_id = f"CI-{uuid.uuid4().hex[:8].upper()}"
    await db.channel_intakes.insert_one({
        "id": channel_intake_id,
        "request_id": request_id,
        "ticket_id": ticket_id,
        "notification_id": notification_id,
        "inbox_id": inbox_id,
        "channel": payload.source or "web",
        "request_type": payload.type,
        "pillar": payload.pillar,
        "status": "new",
        "urgency": urgency,
        "customer_name": customer_name,
        "customer_email": customer_email,
        "customer_phone": customer_phone,
        "preview": f"{service_type} - {pet_name}",
        "message": admin_description[:500] if len(admin_description) > 500 else admin_description,
        "created_at": now,
        "updated_at": now
    })
    logger.info(f"[SERVICE REQUEST] Channel intake created: {channel_intake_id}")
    
    return {
        "success": True,
        "request_id": request_id,
        "ticket_id": ticket_id,
        "notification_id": notification_id,
        "inbox_id": inbox_id,
        "message": f"Your request has been submitted. Our team will contact you shortly."
    }


class ConciergeGoalRequest(BaseModel):
    """Request from ConversationalEntry goal selection"""
    pillar: str
    request_type: str
    request_label: str
    message: str
    pet_name: Optional[str] = None
    source: str = "conversational_entry"


@api_router.post("/concierge/pillar-request")
async def create_concierge_pillar_request(payload: ConciergeGoalRequest):
    """
    Create a pillar-specific request from ConversationalEntry component.
    This is the UNIFIED FLOW endpoint for goal card clicks.
    
    Flow: User clicks goal → Service Desk Ticket → Admin Notification → Member Dashboard
    """
    request_id = f"GOAL-{datetime.now().strftime('%Y%m%d')}-{secrets.token_hex(3).upper()}"
    ticket_id = f"TKT-{secrets.token_hex(4).upper()}"
    now = get_utc_timestamp()
    
    # Map pillar to human-readable names
    pillar_names = {
        "stay": "Stay & Travel",
        "fit": "Fitness & Health",
        "care": "Care & Grooming",
        "dine": "Pet-Friendly Dining",
        "celebrate": "Celebrations",
        "enjoy": "Activities & Fun",
        "learn": "Training & Learning",
        "travel": "Travel & Transport"
    }
    pillar_name = pillar_names.get(payload.pillar, payload.pillar.title())
    
    # Build description
    description = f"""🐾 {pillar_name} Request: {payload.request_label}

Pet: {payload.pet_name or 'Not specified'}
Request Type: {payload.request_type}
Source: {payload.source}

Customer Message:
{payload.message}
"""
    
    # ==================== STEP 1: SERVICE DESK TICKET ====================
    ticket = {
        "id": ticket_id,
        "ticket_id": ticket_id,
        "request_id": request_id,
        "type": "concierge_goal",
        "category": payload.pillar,
        "sub_category": payload.request_type,
        "subject": f"{payload.request_label} - {payload.pet_name or 'Pet'}",
        "description": description,
        "status": "open",
        "priority": "normal",
        "channel": "web",
        "pillar": payload.pillar,
        "source": payload.source,
        "pet_name": payload.pet_name,
        "created_at": now,
        "updated_at": now,
        "assigned_to": None,
        "activity_log": [
            {"action": "created", "timestamp": now, "details": f"Goal selected: {payload.request_label}"}
        ]
    }
    await db.service_desk_tickets.insert_one(ticket)
    logger.info(f"[CONCIERGE GOAL] Ticket created: {ticket_id} for {payload.pillar}/{payload.request_type}")
    
    # ==================== STEP 2: ADMIN NOTIFICATION ====================
    notification_id = f"NOTIF-{secrets.token_hex(4).upper()}"
    await db.admin_notifications.insert_one({
        "id": notification_id,
        "type": "concierge_goal",
        "pillar": payload.pillar,
        "title": f"🎯 {pillar_name}: {payload.request_label}",
        "message": f"{payload.pet_name or 'A customer'} needs help with {payload.request_label}",
        "read": False,
        "status": "unread",
        "ticket_id": ticket_id,
        "request_id": request_id,
        "pet_name": payload.pet_name,
        "link": f"/admin?tab=servicedesk&ticket={ticket_id}",
        "created_at": now
    })
    logger.info(f"[CONCIERGE GOAL] Admin notification created: {notification_id}")
    
    # ==================== STEP 3: PILLAR REQUEST ====================
    await db.pillar_requests.insert_one({
        "id": f"PR-{secrets.token_hex(4).upper()}",
        "ticket_id": ticket_id,
        "request_id": request_id,
        "pillar": payload.pillar,
        "type": payload.request_type,
        "pet_name": payload.pet_name,
        "status": "pending",
        "source": payload.source,
        "created_at": now
    })
    logger.info(f"[CONCIERGE GOAL] Pillar request created for {payload.pillar}")
    
    # ==================== STEP 4: CHANNEL INTAKES ====================
    channel_intake_id = f"CI-{secrets.token_hex(4).upper()}"
    await db.channel_intakes.insert_one({
        "id": channel_intake_id,
        "request_id": request_id,
        "ticket_id": ticket_id,
        "notification_id": notification_id,
        "channel": payload.source,
        "request_type": payload.request_type,
        "pillar": payload.pillar,
        "status": "new",
        "urgency": "medium",
        "pet_name": payload.pet_name,
        "preview": f"{payload.request_label} - {payload.pet_name or 'Pet'}",
        "message": payload.message,
        "created_at": now,
        "updated_at": now
    })
    logger.info(f"[CONCIERGE GOAL] Channel intake created: {channel_intake_id}")
    
    return {
        "success": True,
        "request_id": request_id,
        "ticket_id": ticket_id,
        "message": f"Your {payload.request_label} request has been submitted. Our team will contact you within 24 hours!"
    }


@api_router.post("/services/book")
async def book_service(
    service_id: str = Body(...),
    pet_id: Optional[str] = Body(None),
    preferred_date: Optional[str] = Body(None),
    notes: Optional[str] = Body(None),
    contact_name: str = Body(...),
    contact_phone: str = Body(...),
    contact_email: Optional[str] = Body(None),
    authorization: Optional[str] = Header(None)
):
    """Book a Concierge® service - creates a ticket in the service desk"""
    # Fetch service details
    service = await db.services_master.find_one({"id": service_id}, {"_id": 0})
    if not service:
        raise HTTPException(status_code=404, detail="Service not found")
    
    # Create booking/ticket
    booking_id = f"BK-{uuid.uuid4().hex[:8].upper()}"
    ticket_id = f"TKT-{uuid.uuid4().hex[:8].upper()}"
    
    # Get pet info if provided
    pet_info = None
    if pet_id:
        pet = await db.pets.find_one({"id": pet_id}, {"_id": 0, "name": 1, "breed": 1, "weight": 1})
        if pet:
            pet_info = pet
    
    # Create ticket for service desk
    ticket = {
        "id": ticket_id,
        "booking_id": booking_id,
        "type": "service_booking",
        "service_id": service_id,
        "service_name": service.get("name"),
        "pillar": service.get("pillar"),
        "price": service.get("price"),
        "status": "new",
        "priority": "normal",
        "contact": {
            "name": contact_name,
            "phone": contact_phone,
            "email": contact_email
        },
        "pet_id": pet_id,
        "pet_info": pet_info,
        "preferred_date": preferred_date,
        "notes": notes,
        "created_at": get_utc_timestamp(),
        "updated_at": get_utc_timestamp()
    }
    
    await db.tickets.insert_one(ticket)
    
    now = get_utc_timestamp()
    notification_id = f"NOTIF-{uuid.uuid4().hex[:8].upper()}"
    
    # ==================== STEP 2: SERVICE DESK TICKET ====================
    await db.service_desk_tickets.insert_one({
        **ticket,
        "ticket_id": ticket_id,
        "customer_name": contact_name,
        "customer_phone": contact_phone,
        "customer_email": contact_email
    })
    
    # ==================== STEP 3: ADMIN NOTIFICATION ====================
    await create_admin_notification(
        notification_type="service_booking",
        title=f"🎫 New Service Booking: {service.get('name')}",
        message=f"{contact_name} booked {service.get('name')} for {pet_info.get('name', 'their pet') if pet_info else 'their pet'}",
        category=service.get("pillar", "services"),
        related_id=ticket_id,
        link_to=f"/admin?tab=servicedesk&ticket={ticket_id}",
        priority="high",
        metadata={
            "service_name": service.get("name"),
            "contact_name": contact_name,
            "contact_phone": contact_phone,
            "pet_name": pet_info.get("name") if pet_info else None,
            "preferred_date": preferred_date,
            "booking_id": booking_id
        }
    )
    logger.info(f"[SERVICE BOOKING] Admin notification sent for ticket {ticket_id}")
    
    # ==================== STEP 4: MEMBER NOTIFICATION ====================
    if contact_email:
        member_notif_id = f"MNOTIF-{uuid.uuid4().hex[:8].upper()}"
        await db.member_notifications.insert_one({
            "id": member_notif_id,
            "user_email": contact_email,
            "type": "service_booking_received",
            "title": f"Booking Received: {service.get('name')}",
            "message": f"Your booking for {service.get('name')} has been submitted. We'll confirm shortly!",
            "ticket_id": ticket_id,
            "booking_id": booking_id,
            "pillar": service.get("pillar"),
            "link": "/dashboard?tab=requests",
            "read": False,
            "created_at": now
        })
    
    # ==================== STEP 5: PILLAR REQUEST ====================
    await db.pillar_requests.insert_one({
        "id": f"PR-{uuid.uuid4().hex[:8].upper()}",
        "ticket_id": ticket_id,
        "booking_id": booking_id,
        "pillar": service.get("pillar"),
        "type": "service_booking",
        "service_id": service_id,
        "service_name": service.get("name"),
        "customer_name": contact_name,
        "customer_email": contact_email,
        "pet_id": pet_id,
        "status": "pending",
        "preferred_date": preferred_date,
        "created_at": now
    })
    
    # ==================== STEP 6: CHANNEL INTAKES ====================
    await db.channel_intakes.insert_one({
        "id": f"CI-{uuid.uuid4().hex[:8].upper()}",
        "ticket_id": ticket_id,
        "booking_id": booking_id,
        "notification_id": notification_id,
        "channel": "web",
        "request_type": "service_booking",
        "pillar": service.get("pillar"),
        "status": "new",
        "urgency": "high",
        "customer_name": contact_name,
        "customer_email": contact_email,
        "customer_phone": contact_phone,
        "pet_name": pet_info.get("name") if pet_info else None,
        "preview": f"Service Booking: {service.get('name')}",
        "message": f"Booking for {service.get('name')} on {preferred_date or 'TBD'}",
        "created_at": now,
        "updated_at": now
    })
    logger.info(f"[SERVICE BOOKING] Full unified flow completed for {ticket_id}")
    
    return {
        "success": True,
        "booking_id": booking_id,
        "ticket_id": ticket_id,
        "message": f"Your booking for {service.get('name')} has been received. Our team will contact you shortly."
    }


class UnifiedBookingRequest(BaseModel):
    """Unified booking request for any service type"""
    service_type: str  # grooming, vet, training, walking
    sub_service: Optional[str] = None
    service_name: str
    sub_service_name: Optional[str] = None
    pillar: str
    location_type: str = "home"  # home or salon
    pet: Optional[dict] = None
    customer: dict
    schedule: dict
    additional_notes: Optional[str] = None


@api_router.post("/services/unified-book")
async def unified_service_booking(request: UnifiedBookingRequest):
    """Unified service booking - creates ticket in service desk
    
    This endpoint supports booking any service type (grooming, vet, training, walking)
    without requiring a pre-existing service document.
    
    ENFORCES UNIFIED FLOW: Notification → Service Desk Ticket → Unified Inbox
    """
    from unified_flow_middleware import trigger_unified_flow
    
    # Create booking/ticket IDs
    booking_id = f"BK-{uuid.uuid4().hex[:8].upper()}"
    ticket_id = f"TKT-{uuid.uuid4().hex[:8].upper()}"
    notification_id = f"NOTIF-{uuid.uuid4().hex[:8].upper()}"
    inbox_id = f"INBOX-{uuid.uuid4().hex[:8].upper()}"
    now = get_utc_timestamp()
    
    description = f"""Service Booking Request:
- Service: {request.service_name} - {request.sub_service_name or 'N/A'}
- Location: {request.location_type.title()}
- Date: {request.schedule.get('preferred_date', 'TBD')}
- Time: {request.schedule.get('preferred_time', 'TBD')}
- Address: {request.schedule.get('address', 'N/A')}

Pet Details:
- Name: {request.pet.get('name') if request.pet else 'N/A'}
- Breed: {request.pet.get('breed') if request.pet else 'N/A'}
- Notes: {request.pet.get('notes') if request.pet else 'None'}

Additional Notes: {request.additional_notes or 'None'}
"""
    
    customer_name = request.customer.get("name") if request.customer else "Customer"
    customer_email = request.customer.get("email") if request.customer else None
    customer_phone = request.customer.get("phone") if request.customer else None
    pet_name = request.pet.get("name") if request.pet else "Pet"
    pet_breed = request.pet.get("breed") if request.pet else ""
    
    # ==================== STEP 1: NOTIFICATION (MANDATORY) ====================
    await db.admin_notifications.insert_one({
        "id": notification_id,
        "type": f"service_booking_{request.pillar}",
        "pillar": request.pillar,
        "title": f"New Service Booking - {request.service_name}",
        "message": f"{customer_name} booked {request.service_name} for {pet_name}",
        "read": False,
        "status": "unread",
        "urgency": "medium",
        "ticket_id": ticket_id,
        "inbox_id": inbox_id,
        "booking_id": booking_id,
        "customer": {"name": customer_name, "email": customer_email, "phone": customer_phone},
        "pet": {"name": pet_name, "breed": pet_breed},
        "link": f"/admin?tab=servicedesk&ticket={ticket_id}",
        "created_at": now,
        "read_at": None
    })
    logger.info(f"[UNIFIED FLOW] Service booking notification created: {notification_id}")
    
    # ==================== STEP 2: SERVICE DESK TICKET (MANDATORY) ====================
    ticket = {
        "id": ticket_id,
        "ticket_id": ticket_id,
        "booking_id": booking_id,
        "notification_id": notification_id,
        "inbox_id": inbox_id,
        "type": "service_booking",
        "category": request.pillar,
        "subject": f"{request.service_name} Booking - {request.sub_service_name or request.service_type}",
        "description": description,
        "status": "open",
        "priority": "normal",
        "channel": "web",
        "pillar": request.pillar,
        "service_type": request.service_type,
        "sub_service": request.sub_service,
        "location_type": request.location_type,
        "contact": {
            "name": customer_name,
            "phone": customer_phone,
            "email": customer_email
        },
        "member": {"name": customer_name, "email": customer_email, "phone": customer_phone},
        "pet_info": request.pet,
        "schedule": request.schedule,
        "additional_notes": request.additional_notes,
        "created_at": now,
        "updated_at": now,
        "unified_flow_processed": True
    }
    
    await db.tickets.insert_one(ticket)
    await db.service_desk_tickets.insert_one(ticket)
    logger.info(f"[UNIFIED FLOW] Service desk ticket created: {ticket_id}")
    
    # ==================== STEP 3: UNIFIED INBOX (MANDATORY) ====================
    inbox_entry = {
        "id": inbox_id,
        "request_id": booking_id,
        "ticket_id": ticket_id,
        "notification_id": notification_id,
        "channel": "web",
        "request_type": "service_booking",
        "pillar": request.pillar,
        "category": request.service_type,
        "status": "new",
        "urgency": "medium",
        "customer_name": customer_name,
        "customer_email": customer_email,
        "customer_phone": customer_phone,
        "member": {"name": customer_name, "email": customer_email, "phone": customer_phone},
        "pet": {"name": pet_name, "breed": pet_breed},
        "preview": f"Service Booking: {request.service_name} - {pet_name}",
        "message": description[:200] + "...",
        "full_content": description,
        "metadata": {"booking_id": booking_id, "service_name": request.service_name},
        "tags": ["service_booking", request.pillar, request.service_type],
        "created_at": now,
        "updated_at": now,
        "unified_flow_processed": True
    }
    await db.channel_intakes.insert_one(inbox_entry)
    logger.info(f"[UNIFIED FLOW] Unified inbox entry created: {inbox_id}")
    
    logger.info(f"[UNIFIED FLOW] COMPLETE: Service booking {booking_id} | Notification({notification_id}) → Ticket({ticket_id}) → Inbox({inbox_id})")
    
    # ═══════════════════════════════════════════════════════════════════════════
    # SEND WHATSAPP BOOKING CONFIRMATION
    # ═══════════════════════════════════════════════════════════════════════════
    if customer_phone:
        try:
            await WhatsAppNotifications.service_booked(
                phone=customer_phone,
                user_name=customer_name,
                pet_name=pet_name,
                service_name=request.service_name,
                booking_date=request.schedule.get('preferred_date', 'TBD'),
                booking_time=request.schedule.get('preferred_time')
            )
            logger.info(f"[WHATSAPP] Booking confirmation sent to {customer_phone[:6]}***")
        except Exception as wa_err:
            logger.warning(f"[WHATSAPP] Booking confirmation failed: {wa_err}")
    
    return {
        "success": True,
        "booking_id": booking_id,
        "ticket_id": ticket_id,
        "notification_id": notification_id,
        "inbox_id": inbox_id,
        "message": f"Your booking for {request.service_name} has been received. Our team will contact you shortly.",
        "typical_response_time": "2-4 hours"
    }


# ==================== PRODUCT WISHLIST / LIKES ====================

@api_router.post("/member/wishlist/add")
async def add_to_wishlist(data: dict, current_user: dict = Depends(get_current_user)):
    """Add a product to user's wishlist"""
    product_id = data.get("product_id")
    product_name = data.get("product_name", "")
    product_image = data.get("product_image", "")
    product_price = data.get("product_price", 0)
    
    if not product_id:
        raise HTTPException(status_code=400, detail="product_id is required")
    
    # Add to wishlist collection
    await db.wishlists.update_one(
        {"user_email": current_user["email"], "product_id": product_id},
        {"$set": {
            "user_email": current_user["email"],
            "product_id": product_id,
            "product_name": product_name,
            "product_image": product_image,
            "product_price": product_price,
            "added_at": get_utc_timestamp()
        }},
        upsert=True
    )
    
    return {"message": "Added to wishlist", "product_id": product_id}


@api_router.delete("/member/wishlist/{product_id}")
async def remove_from_wishlist(product_id: str, current_user: dict = Depends(get_current_user)):
    """Remove a product from user's wishlist"""
    result = await db.wishlists.delete_one({
        "user_email": current_user["email"],
        "product_id": product_id
    })
    
    if result.deleted_count == 0:
        raise HTTPException(status_code=404, detail="Product not in wishlist")
    
    return {"message": "Removed from wishlist", "product_id": product_id}


@api_router.get("/member/wishlist")
async def get_wishlist(current_user: dict = Depends(get_current_user)):
    """Get user's wishlist"""
    items = await db.wishlists.find(
        {"user_email": current_user["email"]}, 
        {"_id": 0}
    ).sort("added_at", -1).to_list(100)
    
    return {"wishlist": items, "count": len(items)}


@api_router.get("/admin/wishlists/summary")
async def get_wishlist_summary(admin: dict = Depends(verify_admin)):
    """Admin endpoint: Get summary of all wishlisted products for reminders"""
    # Group by product and count
    pipeline = [
        {"$group": {
            "_id": "$product_id",
            "product_name": {"$first": "$product_name"},
            "product_image": {"$first": "$product_image"},
            "product_price": {"$first": "$product_price"},
            "users_count": {"$sum": 1},
            "user_emails": {"$push": "$user_email"},
            "latest_added": {"$max": "$added_at"}
        }},
        {"$sort": {"users_count": -1}},
        {"$limit": 50}
    ]
    
    results = await db.wishlists.aggregate(pipeline).to_list(50)
    
    return {
        "popular_wishlisted": results,
        "total_wishlisted_products": len(results)
    }


@api_router.get("/products/recommendations/personalized")
async def get_personalized_recommendations(
    user_id: str,
    categories: str = None,
    exclude_ids: str = None,
    limit: int = 6
):
    """Mira-powered personalized product recommendations based on user's pet profile"""
    
    # Get user's pets to understand preferences
    user_pets = await db.pets.find({"user_id": user_id}, {"_id": 0}).to_list(10)
    
    # Extract pet attributes for personalization
    pet_sizes = set()
    pet_life_stages = set()
    pet_allergies = set()
    pet_preferences = set()
    
    for pet in user_pets:
        # Size
        size = pet.get("size") or pet.get("doggy_soul", {}).get("size_category")
        if size:
            pet_sizes.add(size.lower())
        
        # Life stage from age
        age = pet.get("age") or 0
        if isinstance(age, str):
            try:
                age = int(age.replace("years", "").replace("year", "").strip())
            except:
                age = 5
        if age < 1:
            pet_life_stages.add("puppy")
        elif age > 7:
            pet_life_stages.add("senior")
        else:
            pet_life_stages.add("adult")
        
        # Allergies - CRITICAL for filtering
        allergies = pet.get("doggy_soul", {}).get("food_allergies") or pet.get("allergies") or []
        if isinstance(allergies, list):
            for a in allergies:
                if a and a.lower() != "none":
                    pet_allergies.add(a.lower())
        
        # Food preferences
        fav_treats = pet.get("doggy_soul", {}).get("favorite_treats") or []
        if isinstance(fav_treats, list):
            pet_preferences.update([t.lower() for t in fav_treats if t])
    
    # Build query for personalized products
    query = {"in_stock": {"$ne": False}}
    
    # Prioritize products for the pet's size and life stage
    or_conditions = [
        {"tags": {"$in": ["best_seller", "popular", "recommended", "addon"]}},
        {"pillar": "shop"},
        {"pillar": "celebrate"}
    ]
    
    if pet_sizes:
        or_conditions.append({"tags": {"$in": list(pet_sizes)}})
    if pet_life_stages:
        or_conditions.append({"tags": {"$in": list(pet_life_stages)}})
    
    query["$or"] = or_conditions
    
    # Exclude products with allergens
    if pet_allergies:
        query["$nor"] = [{"tags": {"$in": list(pet_allergies)}}]
    
    # Exclude specific products
    if exclude_ids:
        exclude_list = [id.strip() for id in exclude_ids.split(',') if id.strip()]
        if exclude_list:
            query["id"] = {"$nin": exclude_list}
    
    products = await db.products_master.find(
        query,
        {"_id": 0, "id": 1, "name": 1, "price": 1, "image": 1, "images": 1, "category": 1, "tags": 1, "pillar": 1, "description": 1}
    ).sort("created_at", -1).limit(limit * 4).to_list(limit * 4)
    
    # Score and rank products based on pet profile match
    scored_products = []
    for p in products:
        pillar = p.get('pillar', '')
        if pillar in ['stay', 'travel', 'care', 'advisory']:
            continue
        
        score = 0
        tags = [t.lower() for t in p.get('tags', [])]
        
        # Boost for size match
        if pet_sizes and any(s in tags for s in pet_sizes):
            score += 3
        
        # Boost for life stage match
        if pet_life_stages and any(ls in tags for ls in pet_life_stages):
            score += 2
        
        # Boost for preference match
        if pet_preferences and any(pref in tags for pref in pet_preferences):
            score += 2
        
        # Boost for popular items
        if any(t in tags for t in ['best_seller', 'popular']):
            score += 1
        
        p['image'] = p.get('image') or (p.get('images', [None])[0] if p.get('images') else None)
        p['_score'] = score
        p['personalized_reason'] = []
        
        if pet_sizes and any(s in tags for s in pet_sizes):
            p['personalized_reason'].append(f"Perfect for {list(pet_sizes)[0]} dogs")
        if pet_life_stages and any(ls in tags for ls in pet_life_stages):
            p['personalized_reason'].append(f"Great for {list(pet_life_stages)[0]} pets")
        
        scored_products.append(p)
    
    # Sort by score (highest first)
    scored_products.sort(key=lambda x: x.get('_score', 0), reverse=True)
    
    # Clean up internal fields
    result = []
    for p in scored_products[:limit]:
        p.pop('_score', None)
        result.append(p)
    
    return {
        "products": result, 
        "total": len(result),
        "personalized": True,
        "pet_profile": {
            "sizes": list(pet_sizes),
            "life_stages": list(pet_life_stages),
            "excluded_allergens": list(pet_allergies)
        }
    }


@api_router.get("/products/recommendations")
async def get_product_recommendations(
    categories: str = None,  # comma-separated categories
    exclude_ids: str = None,  # comma-separated product IDs to exclude
    limit: int = 6
):
    """Get product recommendations based on categories (for checkout add-ons)"""
    # First try to get products from shop/celebrate pillars with addon tags
    query = {
        "in_stock": {"$ne": False},
        "$or": [
            {"tags": {"$in": ["best_seller", "popular", "recommended", "addon"]}},
            {"pillar": "shop"},
            {"pillar": "celebrate"},
            {"category": {"$in": ["treats", "cakes", "toys", "accessories", "birthday_cakes"]}}
        ]
    }
    
    # Exclude specific products
    if exclude_ids:
        exclude_list = [id.strip() for id in exclude_ids.split(',') if id.strip()]
        if exclude_list:
            query["id"] = {"$nin": exclude_list}
    
    products = await db.products_master.find(
        query,
        {"_id": 0, "id": 1, "name": 1, "price": 1, "image": 1, "images": 1, "category": 1, "tags": 1, "pillar": 1}
    ).sort("created_at", -1).limit(limit * 3).to_list(limit * 3)
    
    # Filter out stay/travel properties and prioritize food/toys
    checkout_friendly = []
    for p in products:
        pillar = p.get('pillar', '')
        if pillar in ['stay', 'travel', 'care', 'advisory']:
            continue  # Skip services
        p['image'] = p.get('image') or (p.get('images', [None])[0] if p.get('images') else None)
        checkout_friendly.append(p)
    
    # Prioritize by tags
    prioritized = []
    others = []
    for p in checkout_friendly:
        tags = p.get('tags', [])
        if any(t in tags for t in ['best_seller', 'popular', 'addon', 'recommended']):
            prioritized.append(p)
        else:
            others.append(p)
    
    result = (prioritized + others)[:limit]
    return {"products": result, "total": len(result)}


@api_router.get("/products/recommendations/for-pet/{pet_id}")
async def get_pet_recommendations(pet_id: str, limit: int = 20, pillar: str = None):
    """Get personalized product recommendations based on pet profile and optional pillar filter"""
    # Fetch pet profile
    pet = await db.pets.find_one({"id": pet_id}, {"_id": 0})
    if not pet:
        raise HTTPException(status_code=404, detail="Pet not found")
    
    # Extract pet attributes for filtering
    weight = pet.get("weight")
    birth_date = pet.get("birth_date")
    breed = pet.get("breed", "").lower()
    personality = pet.get("personality", []) or []
    preferences = pet.get("preferences") or {}
    allergies = preferences.get("allergies", []) if preferences else []
    if isinstance(allergies, str):
        allergies = [a.strip().lower() for a in allergies.split(",") if a.strip()]
    treat_size = preferences.get("treat_size", "") if preferences else ""
    
    # Determine size category from weight (handle string conversion)
    size_category = "all-sizes"
    if weight:
        try:
            weight_num = float(weight) if isinstance(weight, str) else weight
            if weight_num < 10:
                size_category = "small-dog"
            elif weight_num < 25:
                size_category = "medium-dog"
            elif weight_num < 45:
                size_category = "large-dog"
            else:
                size_category = "giant-breed"
        except (ValueError, TypeError):
            pass  # Keep default "all-sizes"
    
    # Determine age category from birth date
    age_category = "adult"
    if birth_date:
        try:
            from dateutil import parser
            from datetime import datetime, timezone
            birth = parser.parse(birth_date)
            age_months = (datetime.now(timezone.utc) - birth.replace(tzinfo=timezone.utc)).days / 30
            if age_months < 12:
                age_category = "puppy"
            elif age_months > 84:  # 7 years
                age_category = "senior"
        except:
            pass
    
    # Build recommendation query - more inclusive
    query = {
        "$or": [
            {"in_stock": True},
            {"in_stock": {"$exists": False}}
        ]
    }
    
    # ═══════════════════════════════════════════════════════════════════════════════
    # CARE PILLAR: Prioritize comprehensive care products with good_for_tags
    # These have size/coat/life_stage/temperament/intent tags
    # ═══════════════════════════════════════════════════════════════════════════════
    if pillar == "care":
        # First, get comprehensive care products (with good_for_tags)
        care_query = {
            "pillar": "care",
            "good_for_tags": {"$exists": True, "$ne": []}
        }
        comprehensive_products = await db.products_master.find(care_query, {"_id": 0}).limit(20).to_list(20)
        
        # Determine pet's size category for matching
        size_tag = "medium"  # default
        if weight:
            try:
                weight_num = float(weight) if isinstance(weight, str) else weight
                if weight_num < 10:
                    size_tag = "small"
                elif weight_num < 25:
                    size_tag = "medium"
                else:
                    size_tag = "large"
            except:
                pass
        
        # Score comprehensive products based on pet profile match
        scored_comprehensive = []
        for p in comprehensive_products:
            good_for_tags = p.get("good_for_tags", [])
            score = 50  # Base score for comprehensive products
            
            # Size match
            if size_tag in good_for_tags or "all" in good_for_tags:
                score += 25
            
            # Age match
            if age_category in good_for_tags:
                score += 20
            
            # Coat type match (from pet soul data)
            soul = pet.get("soul") or {}
            coat_type = soul.get("coat_type", "").lower().replace(" ", "_")
            if coat_type and coat_type in good_for_tags:
                score += 15
            
            # Temperament match
            temperament = soul.get("temperament", "").lower()
            if temperament and temperament in good_for_tags:
                score += 10
            
            scored_comprehensive.append({
                **p,
                "score": score,
                "why_it_fits": f"Perfect for {size_tag} {age_category}s" if score > 60 else "Great for everyday care"
            })
        
        # Sort by score
        scored_comprehensive.sort(key=lambda x: x.get("score", 0), reverse=True)
        
        return {"recommendations": scored_comprehensive[:limit]}
    
    # For other pillars, continue with original logic
    # Pillar filter - prioritize products from this pillar
    if pillar:
        query["pillar"] = pillar
    
    # Exclude products with allergies in their tags if allergies exist
    if allergies and len(allergies) > 0 and allergies[0].lower() not in ['no', 'none', '']:
        clean_allergies = [a.lower() for a in allergies if a.lower() not in ['no', 'none', '']]
        if clean_allergies:
            query["tags"] = {"$nin": clean_allergies}
    
    # Fetch products - get more variety
    products = await db.products_master.find(query, {"_id": 0}).limit(limit * 3).to_list(limit * 3)
    
    # DOCTRINE: Pillar-first, then Pet-first (breed), then general
    # When on a pillar page, ONLY show products from that pillar
    # Breed matching happens WITHIN the pillar context
    
    # 🎯 PRIORITY 1: Check breed_products collection for personalized PICKS
    # These are specially created products for each breed (Birthday Cake, Mug, Bandana, etc.)
    if breed:
        breed_products_query = {
            "is_active": True,
            "$or": [
                {"who_for": {"$regex": breed, "$options": "i"}},
                {"breed_tags.breeds": {"$elemMatch": {"$regex": breed, "$options": "i"}}}
            ]
        }
        # Add pillar filter if specified
        if pillar:
            breed_products_query["pillars"] = pillar
        
        breed_specific_products = await db.breed_products.find(breed_products_query, {"_id": 0}).limit(8).to_list(8)
        
        if breed_specific_products:
            logger.info(f"[PICKS] Found {len(breed_specific_products)} breed-specific products for {breed}")
            # Add these at the front - they're the most relevant!
            products = breed_specific_products + products
    
    # Fetch breed-specific products WITHIN the pillar if breed is known (fallback from products_master)
    if breed and pillar:
        breed_pillar_query = {
            "pillar": pillar,
            "$or": [
                {"name": {"$regex": breed, "$options": "i"}},
                {"tags": {"$elemMatch": {"$regex": breed, "$options": "i"}}},
                {"description": {"$regex": breed, "$options": "i"}}
            ]
        }
        breed_pillar_products = await db.products_master.find(breed_pillar_query, {"_id": 0}).limit(10).to_list(10)
        # Add breed-specific pillar products (avoid duplicates)
        existing_ids = {p.get('id') for p in products}
        products = products + [p for p in breed_pillar_products if p.get('id') not in existing_ids]
    
    # If pillar specified but no products found, create concierge suggestion cards
    # (Per doctrine: "If a product is not there we create non-priced concierge cards")
    if pillar and len(products) == 0:
        # Create concierge suggestion cards for this pillar
        concierge_suggestions = [
            {
                "id": f"concierge-{pillar}-1",
                "name": f"Custom {pillar.title()} Request for {pet.get('name', 'Your Pet')}",
                "description": f"Can't find what you need? Let our concierge help find the perfect {pillar} solution for {pet.get('name', 'your pet')}.",
                "price": None,
                "is_concierge": True,
                "pillar": pillar,
                "cta": "Ask Mira"
            }
        ]
        products = concierge_suggestions
    
    # ONLY add celebrate products for celebrate/dine pillars (not when pillar is missing)
    if pillar and pillar in ["celebrate", "dine"]:
        celebrate_products = await db.celebrate_products.find({}, {"_id": 0}).limit(10).to_list(10)
        products.extend(celebrate_products)
    
    # Score products based on relevance to pet
    scored_products = []
    
    # ═══════════════════════════════════════════════════════════════════════════════
    # BREED EXCLUSION LIST - Products for OTHER breeds should be excluded
    # This prevents "Shih Tzu Cake" from showing for a Maltese dog
    # ═══════════════════════════════════════════════════════════════════════════════
    ALL_BREED_NAMES = [
        "labrador", "golden retriever", "german shepherd", "beagle", "bulldog", 
        "poodle", "rottweiler", "yorkshire", "boxer", "dachshund", "siberian husky", 
        "husky", "doberman", "great dane", "shih tzu", "shihtzu", "pug", "chihuahua", 
        "pomeranian", "maltese", "cocker spaniel", "border collie", "cavalier", 
        "french bulldog", "indie", "indian pariah", "american bully", "chow chow", 
        "dalmatian", "jack russell", "lhasa apso", "italian greyhound", "scottish terrier", 
        "st bernard", "schnoodle", "irish setter", "toy poodle", "mutt"
    ]
    
    for p in products:
        score = 0
        tags = [t.lower() for t in (p.get("tags") or p.get("intelligent_tags") or [])]
        name_lower = (p.get("name") or p.get("title") or "").lower()
        category = (p.get("category") or "").lower()
        
        # ═══════════════════════════════════════════════════════════════════════════════
        # CRITICAL: EXCLUDE products explicitly for OTHER breeds
        # If product name contains a breed name that's NOT the pet's breed, SKIP it
        # ═══════════════════════════════════════════════════════════════════════════════
        if breed:
            breed_lower = breed.lower().strip()
            breed_words = breed_lower.split()
            breed_clean = breed_lower.replace(" ", "")  # "shih tzu" -> "shihtzu"
            
            # Check if product name contains ANY breed name
            product_is_for_other_breed = False
            for other_breed in ALL_BREED_NAMES:
                # Skip if this is the current pet's breed
                if other_breed in breed_lower or breed_clean == other_breed.replace(" ", ""):
                    continue
                # Check if product name explicitly mentions this other breed
                if other_breed in name_lower or other_breed.replace(" ", "") in name_lower.replace(" ", ""):
                    product_is_for_other_breed = True
                    break
            
            if product_is_for_other_breed:
                # Skip products explicitly for other breeds
                continue
        
        # Pillar match bonus
        if pillar and p.get("pillar") == pillar:
            score += 20
        
        # Category bonuses for treats/food
        if category in ["treats", "food", "snacks", "cakes"]:
            score += 15
        if "treat" in name_lower or "cake" in name_lower or "snack" in name_lower:
            score += 10
        
        # Size match bonus
        if size_category in tags or "all-sizes" in tags or any(size_category.replace("-", " ") in t for t in tags):
            score += 10
        # Small dogs usually like smaller treats
        if size_category == "small-dog" and any(word in name_lower for word in ["mini", "small", "bite", "tiny"]):
            score += 8
        
        # Age match bonus  
        if age_category in tags or "all-ages" in tags:
            score += 10
        # Special bonus for age-appropriate products
        if age_category == "puppy" and any(word in name_lower or word in tags for word in ["puppy", "starter", "young"]):
            score += 12
        if age_category == "senior" and any(word in name_lower or word in tags for word in ["senior", "joint", "mobility", "gentle"]):
            score += 12
        
        # Breed-specific bonus - only within pillar context (pet's own breed gets bonus)
        if breed:
            for bw in breed_words:
                if bw in tags or bw in name_lower:
                    score += 15  # Moderate breed match bonus
            
            # Special bonus for breed products ONLY if matching pillar or no pillar filter
            # Cakes get bonus only on celebrate/dine pillars
            if "cake" in name_lower or category in ["cakes", "breed-cakes"]:
                if not pillar or pillar in ["celebrate", "dine"]:
                    for bw in breed_words:
                        if bw in name_lower:
                            score += 30  # Bonus for breed-specific cakes on celebrate pillar
            
            # Check for breed in product name variations
            if breed_clean in name_lower.replace(" ", ""):
                score += 15
        
        # Personality-based bonus
        if personality:
            for trait in personality:
                trait_lower = trait.lower() if isinstance(trait, str) else ""
                if "active" in trait_lower or "energetic" in trait_lower:
                    if any(word in name_lower or word in tags for word in ["active", "energy", "play", "sport"]):
                        score += 8
                if "calm" in trait_lower or "lazy" in trait_lower:
                    if any(word in name_lower or word in tags for word in ["calm", "relaxing", "gentle", "comfort"]):
                        score += 8
                if "anxious" in trait_lower or "nervous" in trait_lower:
                    if any(word in name_lower or word in tags for word in ["calming", "anxiety", "relaxing", "soothing"]):
                        score += 10
        
        # Allergy safety check
        is_safe = True
        if allergies:
            for allergy in allergies:
                if allergy.lower() not in ['no', 'none', ''] and allergy.lower() in tags:
                    is_safe = False
                    break
                if f"{allergy.lower()}-free" in tags:
                    score += 5  # Bonus for explicitly allergen-free
        
        if not is_safe:
            continue  # Skip products containing allergens
        
        # Treat size preference
        if treat_size:
            if treat_size.lower() in name_lower:
                score += 5
        
        # Has image bonus (important for display)
        if p.get("image"):
            score += 3
        
        # Is recommended/bestseller bonus
        if p.get("is_recommended") or p.get("isBestseller"):
            score += 8
        
        scored_products.append((score, p))
    
    # Sort by score and return top matches
    scored_products.sort(key=lambda x: -x[0])
    recommendations = [p for _, p in scored_products[:limit]]
    
    return {
        "pet": {
            "name": pet.get("name"),
            "breed": breed,
            "size_category": size_category,
            "age_category": age_category,
            "personality": personality,
            "allergies": allergies
        },
        "recommendations": recommendations,
        "total": len(recommendations),
        "pillar": pillar,
        "filters_applied": {
            "size": size_category,
            "age": age_category,
            "breed": breed,
            "personality": personality,
            "excluded_allergens": allergies,
            "pillar": pillar
        }
    }


# ==================== BUYING BEHAVIOR TRACKING ====================

@api_router.get("/buying-behavior/pet/{pet_id}")
async def get_pet_purchase_history(pet_id: str, limit: int = 50):
    """Get purchase history for a specific pet"""
    # Get orders that include this pet
    orders = await db.orders.find(
        {"$or": [
            {"pet_id": pet_id},
            {"pets": pet_id},
            {"items.pet_id": pet_id}
        ]},
        {"_id": 0}
    ).sort("created_at", -1).limit(limit).to_list(limit)
    
    # Extract purchased products
    purchased_products = []
    product_frequency = {}
    
    for order in orders:
        items = order.get("items") or order.get("line_items") or []
        for item in items:
            product_id = item.get("product_id") or item.get("id")
            if product_id:
                product_frequency[product_id] = product_frequency.get(product_id, 0) + 1
                purchased_products.append({
                    "product_id": product_id,
                    "name": item.get("name") or item.get("title"),
                    "quantity": item.get("quantity", 1),
                    "price": item.get("price"),
                    "ordered_at": order.get("created_at")
                })
    
    # Get most purchased products
    most_purchased = sorted(product_frequency.items(), key=lambda x: -x[1])[:10]
    
    return {
        "pet_id": pet_id,
        "total_orders": len(orders),
        "purchased_products": purchased_products[:limit],
        "most_purchased": [{"product_id": p[0], "count": p[1]} for p in most_purchased],
        "product_frequency": product_frequency
    }


@api_router.get("/buying-behavior/frequently-bought-together/{product_id}")
async def get_frequently_bought_together(product_id: str, limit: int = 5):
    """Get products frequently bought together with this product"""
    # Find orders that contain this product
    orders = await db.orders.find(
        {"$or": [
            {"items.product_id": product_id},
            {"items.id": product_id},
            {"line_items.product_id": product_id}
        ]},
        {"_id": 0, "items": 1, "line_items": 1}
    ).limit(100).to_list(100)
    
    # Count co-purchased products
    co_purchase_count = {}
    
    for order in orders:
        items = order.get("items") or order.get("line_items") or []
        product_ids_in_order = []
        
        for item in items:
            item_id = item.get("product_id") or item.get("id")
            if item_id and item_id != product_id:
                product_ids_in_order.append(item_id)
        
        # Count each co-purchased product
        for other_id in product_ids_in_order:
            co_purchase_count[other_id] = co_purchase_count.get(other_id, 0) + 1
    
    # Get top co-purchased products
    top_co_purchased = sorted(co_purchase_count.items(), key=lambda x: -x[1])[:limit]
    
    # Fetch product details
    result_products = []
    for prod_id, count in top_co_purchased:
        product = await db.products_master.find_one(
            {"$or": [{"id": prod_id}, {"shopify_id": prod_id}]},
            {"_id": 0}
        )
        if product:
            product["co_purchase_count"] = count
            result_products.append(product)
    
    return {
        "product_id": product_id,
        "frequently_bought_together": result_products,
        "total_orders_analyzed": len(orders)
    }


@api_router.get("/buying-behavior/repeat-purchase-suggestions/{pet_id}")
async def get_repeat_purchase_suggestions(pet_id: str, limit: int = 6):
    """Get repeat purchase suggestions for consumable products the pet has bought before"""
    from datetime import datetime, timezone, timedelta
    
    # Get pet's order history
    orders = await db.orders.find(
        {"$or": [
            {"pet_id": pet_id},
            {"pets": pet_id},
            {"items.pet_id": pet_id}
        ]},
        {"_id": 0}
    ).sort("created_at", -1).limit(50).to_list(50)
    
    # Track consumable products
    consumable_categories = ["treats", "food", "snacks", "meals", "toppers", "supplements", "grooming-supplies"]
    product_last_purchased = {}
    product_details_cache = {}
    
    for order in orders:
        order_date = order.get("created_at")
        items = order.get("items") or order.get("line_items") or []
        
        for item in items:
            product_id = item.get("product_id") or item.get("id")
            if not product_id:
                continue
            
            # Get product details if not cached
            if product_id not in product_details_cache:
                product = await db.products_master.find_one(
                    {"$or": [{"id": product_id}, {"shopify_id": product_id}]},
                    {"_id": 0}
                )
                if product:
                    product_details_cache[product_id] = product
            
            product = product_details_cache.get(product_id)
            if not product:
                continue
            
            # Check if it's a consumable
            category = (product.get("category") or "").lower()
            tags = [t.lower() for t in (product.get("tags") or [])]
            
            is_consumable = (
                category in consumable_categories or
                any(cat in tags for cat in consumable_categories) or
                any(word in category for word in ["food", "treat", "snack", "meal"])
            )
            
            if is_consumable:
                if product_id not in product_last_purchased:
                    product_last_purchased[product_id] = {
                        "product": product,
                        "last_ordered": order_date,
                        "times_ordered": 0
                    }
                product_last_purchased[product_id]["times_ordered"] += 1
    
    # Sort by times ordered (most frequently purchased first)
    suggestions = sorted(
        product_last_purchased.values(),
        key=lambda x: -x["times_ordered"]
    )[:limit]
    
    # Calculate days since last purchase for each
    now = datetime.now(timezone.utc)
    result = []
    for item in suggestions:
        product = item["product"]
        last_ordered = item["last_ordered"]
        days_since = None
        
        if last_ordered:
            try:
                if isinstance(last_ordered, str):
                    from dateutil import parser
                    last_ordered = parser.parse(last_ordered)
                if last_ordered.tzinfo is None:
                    last_ordered = last_ordered.replace(tzinfo=timezone.utc)
                days_since = (now - last_ordered).days
            except:
                pass
        
        result.append({
            **product,
            "times_ordered": item["times_ordered"],
            "days_since_last_purchase": days_since,
            "reorder_suggested": days_since is not None and days_since > 14
        })
    
    return {
        "pet_id": pet_id,
        "repeat_suggestions": result,
        "total_consumables_tracked": len(product_last_purchased)
    }


# ─────────────────────────────────────────────────────────────────────────────
# SOUL-RANKED PRODUCTS  — pillar tab product scoring based on pet soul profile
# Used by SoulPillarExpanded.jsx across all 8 celebrate pillars
# ─────────────────────────────────────────────────────────────────────────────

def _to_str_list(val) -> list:
    """Safely convert string or list to a list of lowercase strings."""
    if not val:
        return []
    if isinstance(val, list):
        return [str(v).lower().strip() for v in val if v and str(v).lower().strip() != 'none']
    return [s.lower().strip() for s in str(val).replace(';', ',').split(',') if s.strip() and s.strip().lower() != 'none']


def _soul_score(product: dict, soul: dict, pet: dict) -> int:
    """
    Score a product against a pet's soul profile.
    Returns int score. Negative = should be excluded (allergen).
    Higher score = better match.
    """
    name  = (product.get('name') or '').lower()
    desc  = (product.get('description') or '').lower()
    tags  = [str(t).lower() for t in (product.get('tags') or [])]
    text  = f"{name} {desc} {' '.join(tags)}"

    score = 0

    # ── Allergen hard exclusion ──────────────────────────────────────────────
    allergies = _to_str_list(soul.get('food_allergies') or pet.get('food_allergies'))
    for allergen in allergies:
        if len(allergen) > 2 and allergen in text:
            return -999  # Exclude completely

    # ── Favourite treats / protein (+30 per match) ──────────────────────────
    for treat in _to_str_list(soul.get('favorite_treats') or soul.get('favourite_treats')):
        if treat in text:
            score += 30
    if (soul.get('favorite_protein') or '').lower() in text:
        score += 20

    # ── Treat texture preference ─────────────────────────────────────────────
    treat_pref = (soul.get('treat_preference') or '').lower()
    if 'soft' in treat_pref or 'chewy' in treat_pref:
        if any(w in text for w in ['soft', 'chewy', 'moist', 'tender', 'pupcake']):
            score += 15
    elif 'crunchy' in treat_pref or 'hard' in treat_pref:
        if any(w in text for w in ['crunchy', 'biscuit', 'crunch', 'dry', 'hard']):
            score += 15

    # ── Diet flags ───────────────────────────────────────────────────────────
    if soul.get('prefers_grain_free'):
        if any(w in text for w in ['grain-free', 'grain free', 'gluten-free', 'gluten free']):
            score += 12
    if soul.get('sensitive_stomach') in [True, 'Yes', 'Sometimes', 'yes', 'sometimes']:
        if any(w in text for w in ['digestive', 'gentle', 'sensitive', 'probiotic', 'stomach']):
            score += 18

    # ── Favourite activities / play style (+25) ──────────────────────────────
    fav_activity = (soul.get('favorite_activity') or '').lower()
    play_style   = (soul.get('play_style') or '').lower()
    for kw in ['fetch', 'ball', 'frisbee', 'tug', 'sniff', 'puzzle', 'swim', 'run', 'chase']:
        if kw in fav_activity and kw in text:
            score += 25
    if 'human' in play_style or 'together' in play_style or 'owner' in play_style:
        if any(w in text for w in ['interactive', 'tug', 'human', 'together', 'bond']):
            score += 15

    # ── Energy level ─────────────────────────────────────────────────────────
    energy = (soul.get('energy_level') or '').lower()
    if 'high' in energy:
        if any(w in text for w in ['active', 'outdoor', 'fetch', 'agility', 'energetic', 'run']):
            score += 12
    elif 'low' in energy or 'calm' in energy:
        if any(w in text for w in ['calm', 'gentle', 'slow', 'sniff', 'puzzle', 'relaxing']):
            score += 12

    # ── Life stage ───────────────────────────────────────────────────────────
    life_stage   = (soul.get('life_stage') or '').lower()
    age_raw      = pet.get('age') or soul.get('age') or 0
    try:
        age_int = int(str(age_raw).split()[0])
    except (ValueError, TypeError):
        age_int = 4
    is_senior = age_int >= 7 or 'senior' in life_stage
    is_puppy  = age_int <= 1 or 'puppy' in life_stage
    if is_senior:
        if any(w in text for w in ['senior', 'joint', 'hip', 'gentle', 'supplement', 'memory', 'calm', 'elder']):
            score += 22
    if is_puppy:
        if any(w in text for w in ['puppy', 'young', 'starter', 'basic', 'intro', 'foundation']):
            score += 22

    # ── Breed match (+20) ────────────────────────────────────────────────────
    breed = (pet.get('breed') or soul.get('breed') or '').lower()
    if breed and len(breed) > 3 and breed in text:
        score += 20

    # ── Grooming traits ───────────────────────────────────────────────────────
    groom_style = (soul.get('grooming_style') or '').lower()
    if 'salon' in groom_style:
        if any(w in text for w in ['salon', 'professional', 'grooming service', 'spa']):
            score += 15

    # ── Training ─────────────────────────────────────────────────────────────
    train_response = (soul.get('training_response') or '').lower()
    if 'treat' in train_response or 'food' in (soul.get('motivation_type') or '').lower():
        if any(w in text for w in ['training treat', 'training', 'reward', 'lure']):
            score += 15

    # ── Social / celebration preferences ────────────────────────────────────
    if soul.get('loves_celebrations'):
        if any(w in text for w in ['birthday', 'celebrate', 'party', 'pawty', 'gotcha', 'anniversary']):
            score += 15

    # ── Celebration birthday feast style ─────────────────────────────────────
    feast_style = (soul.get('birthday_feast_style') or '').lower()
    if 'big' in feast_style or 'show stopper' in feast_style:
        if any(w in text for w in ['large', 'big', 'grand', 'special', 'premium', 'wow', 'show']):
            score += 18

    # ── Travel / adventure ───────────────────────────────────────────────────
    if (soul.get('car_rides') or '').lower() in ['loves them', 'loves', 'yes']:
        if any(w in text for w in ['car', 'travel', 'on-the-go', 'portable', 'adventure']):
            score += 12

    return score


@api_router.get("/products/soul-ranked")
async def get_soul_ranked_products(
    category: str,
    pet_id: str,
    limit: int = 8
):
    """
    Returns products from a given category, re-ranked by pet soul profile.
    Powers SoulPillarExpanded.jsx across all 8 celebrate pillars.
    Products matching the pet's traits appear first; allergen products are excluded.
    """
    # ── Fetch pet and soul profile ───────────────────────────────────────────
    pet = await db.pets.find_one({"id": pet_id}, {"_id": 0})
    soul = (pet or {}).get('doggy_soul_answers') or {}

    # ── Fetch products for this category ─────────────────────────────────────
    raw = await db.products_master.find(
        {"category": category, "is_active": {"$ne": False}},
        {"_id": 0}
    ).limit(50).to_list(50)

    if not raw:
        # Fallback: return un-ranked products (category may not exist)
        return {"products": [], "personalized": False, "pet_name": None}

    # ── Score + sort ─────────────────────────────────────────────────────────
    scored = []
    for p in raw:
        s = _soul_score(p, soul, pet or {})
        if s > -900:  # Not excluded by allergen
            scored.append({**p, "_soul_score": s})

    scored.sort(key=lambda x: x["_soul_score"], reverse=True)

    pet_name = (pet or {}).get('name') or None

    return {
        "products": scored[:limit],
        "personalized": bool(pet),
        "pet_name": pet_name,
        "top_score": scored[0]["_soul_score"] if scored else 0,
    }


@api_router.get("/products/{product_id}")
async def get_product_detail(product_id: str):
    """Get single product by ID or handle for detail page"""
    # Try products collection first - search by id, shopify_id, or shopify_handle
    product = await db.products_master.find_one(
        {"$or": [
            {"id": product_id}, 
            {"shopify_id": product_id},
            {"shopify_handle": product_id}
        ]},
        {"_id": 0}
    )
    
    if not product:
        # Try unified_products
        product = await db.unified_products.find_one(
            {"$or": [{"id": product_id}, {"sku": product_id}, {"handle": product_id}]},
            {"_id": 0}
        )
    
    if not product:
        # 🎯 Try breed_products collection (PICKS feature - personalized breed products)
        product = await db.breed_products.find_one(
            {"id": product_id},
            {"_id": 0}
        )
    
    if not product:
        raise HTTPException(status_code=404, detail="Product not found")
    
    return {"product": product}


@api_router.get("/products/{product_id}/related")
async def get_related_products(product_id: str, limit: int = 4, pillar: str = None):
    """Get products that go well with the specified product - pillar-aware smart recommendations"""
    
    # Find the current product
    product = await db.products_master.find_one(
        {"$or": [{"id": product_id}, {"shopify_id": product_id}]},
        {"_id": 0}
    )
    
    if not product:
        return {"related": [], "bundles": []}
    
    current_category = product.get("category", "")
    current_subcategory = product.get("subcategory", "")
    current_price = product.get("price", 0)
    product_pillar = pillar or product.get("pillar", current_category) or "celebrate"
    
    # ==================== PILLAR-SPECIFIC UPSELL MAPS ====================
    # These map categories/subcategories to complementary items
    pillar_upsell_map = {
        "celebrate": {
            "cakes": ["treats", "accessories", "bandanas"],
            "pupcakes": ["treats", "accessories", "bandanas"],
            "dognuts": ["treats", "cakes", "accessories"],
            "treats": ["cakes", "accessories"],
            "default": ["treats", "cakes", "accessories"]
        },
        "travel": {
            "crate": ["calming", "accessory", "carrier"],
            "carrier": ["calming", "accessory", "safety"],
            "harness": ["calming", "accessory", "safety"],
            "calming": ["carrier", "accessory", "safety"],
            "accessory": ["calming", "carrier", "safety"],
            "safety": ["calming", "accessory", "carrier"],
            "comfort": ["calming", "accessory"],
            "default": ["calming", "accessory", "carrier"]
        },
        "stay": {
            "comfort": ["calming", "accessory"],
            "default": ["comfort", "calming"]
        },
        "dine": {
            "fresh": ["treats", "supplements"],
            "meals": ["treats", "supplements"],
            "default": ["treats", "supplements"]
        },
        "care": {
            "grooming": ["supplements", "hygiene"],
            "supplements": ["grooming", "hygiene"],
            "hygiene": ["grooming", "supplements"],
            "default": ["supplements", "grooming"]
        },
        "shop": {
            "toys": ["treats", "accessories"],
            "accessories": ["toys", "treats"],
            "default": ["treats", "accessories"]
        }
    }
    
    # Get the upsell map for this pillar
    upsell_map = pillar_upsell_map.get(product_pillar, pillar_upsell_map.get("celebrate", {}))
    
    # Get complementary subcategories based on current subcategory or category
    complementary = upsell_map.get(current_subcategory) or upsell_map.get(current_category) or upsell_map.get("default", ["treats", "accessories"])
    
    related_products = []
    
    # For pan-india category, prioritize pan-india shippable products
    if current_category == "pan-india":
        pan_india_products = await db.products_master.find(
            {"category": "pan-india", "id": {"$ne": product_id}},
            {"_id": 0}
        ).limit(limit).to_list(limit)
        related_products.extend(pan_india_products)
    else:
        # Strategy 1: Find products in same pillar with complementary subcategories
        for comp_subcat in complementary:
            subcat_products = await db.products_master.find(
                {
                    "$or": [
                        {"category": product_pillar, "subcategory": comp_subcat},
                        {"subcategory": comp_subcat},
                        {"category": comp_subcat}
                    ],
                    "id": {"$ne": product_id}
                },
                {"_id": 0}
            ).limit(3).to_list(3)
            related_products.extend(subcat_products)
        
        # Strategy 2: If not enough, get more from same pillar
        if len(related_products) < limit:
            remaining = limit - len(related_products)
            existing_ids = {product_id} | {p.get("id") for p in related_products}
            pillar_products = await db.products_master.find(
                {
                    "$or": [
                        {"pillar": product_pillar},
                        {"category": product_pillar}
                    ],
                    "id": {"$nin": list(existing_ids)}
                },
                {"_id": 0}
            ).limit(remaining).to_list(remaining)
            related_products.extend(pillar_products)
        
        # Strategy 3: If still not enough, get popular products
        if len(related_products) < limit:
            remaining = limit - len(related_products)
            existing_ids = {product_id} | {p.get("id") for p in related_products}
            popular = await db.products_master.find(
                {
                    "id": {"$nin": list(existing_ids)},
                    "category": {"$in": ["treats", "accessories"]}
                },
                {"_id": 0}
            ).limit(remaining).to_list(remaining)
            related_products.extend(popular)
    
    # Also get similar products from same category (different price range)
    similar = await db.products_master.find(
        {
            "category": current_category,
            "id": {"$ne": product_id},
            "price": {"$gte": current_price * 0.5, "$lte": current_price * 1.5}
        },
        {"_id": 0}
    ).limit(2).to_list(2)
    
    # Remove duplicates and limit
    seen_ids = {product_id}
    unique_related = []
    for p in related_products + similar:
        pid = p.get("id") or p.get("shopify_id")
        if pid and pid not in seen_ids:
            seen_ids.add(pid)
            unique_related.append(p)
            if len(unique_related) >= limit:
                break
    
    # ==================== PILLAR-SPECIFIC BUNDLES ====================
    bundles = []
    
    if product_pillar == "celebrate" and current_category in ["cakes", "pupcakes"]:
        treat = await db.products_master.find_one({"category": "treats"}, {"_id": 0})
        bandana = await db.products_master.find_one({"category": {"$in": ["accessories", "bandanas"]}}, {"_id": 0})
        if treat and bandana:
            bundle_price = current_price + treat.get("price", 0) + bandana.get("price", 0)
            bundles.append({
                "name": "🎉 Celebration Bundle",
                "description": "Complete the pawty!",
                "items": [product, treat, bandana],
                "originalPrice": bundle_price,
                "bundlePrice": int(bundle_price * 0.9),
                "savings": int(bundle_price * 0.1)
            })
    
    elif product_pillar == "travel":
        calming = await db.products_master.find_one({"subcategory": "calming"}, {"_id": 0})
        accessory = await db.products_master.find_one({"subcategory": "accessory"}, {"_id": 0})
        if calming and accessory:
            bundle_price = current_price + calming.get("price", 0) + accessory.get("price", 0)
            bundles.append({
                "name": "✈️ Travel Ready Bundle",
                "description": "Everything for a stress-free trip!",
                "items": [product, calming, accessory],
                "originalPrice": bundle_price,
                "bundlePrice": int(bundle_price * 0.85),
                "savings": int(bundle_price * 0.15)
            })
    
    return {
        "related": unique_related,
        "bundles": bundles,
        "category": current_category,
        "subcategory": current_subcategory,
        "pillar": product_pillar
    }



# ==================== SOUL BUILDER SAVE ENDPOINT ====================

@api_router.post("/pet-soul/save-answers")
async def save_soul_builder_answers(request: Request, authorization: Optional[str] = Header(None)):
    """
    Save soul answers from the Soul Builder gamified questionnaire.
    Creates or updates a pet with all soul answers.
    
    CANONICAL PROFILE UPDATE:
    - This is THE single source of truth for "What Mira knows"
    - Answers are MERGED, never replaced (unless explicitly editing)
    - All surfaces read from this canonical profile
    """
    try:
        # Get user from authorization header
        user = None
        if authorization:
            try:
                token = authorization.replace("Bearer ", "") if authorization.startswith("Bearer ") else authorization
                payload = jwt.decode(token, SECRET_KEY, algorithms=[ALGORITHM])
                email = payload.get("sub")
                if email:
                    user = await db.users.find_one({"email": email.lower()})
            except Exception:
                pass
        
        if not user:
            raise HTTPException(status_code=401, detail="Authentication required")
        
        data = await request.json()
        pet_name = data.get("pet_name", "")
        pet_id_from_request = data.get("pet_id")
        new_soul_answers = data.get("soul_answers", {})
        soul_score = data.get("soul_score", 0)
        pet_data = data.get("pet_data", {})
        answered_question_ids = data.get("answered_question_ids", [])
        
        if not pet_name:
            raise HTTPException(status_code=400, detail="Pet name required")
        
        # Find existing pet by ID first, then by name
        existing_pet = None
        if pet_id_from_request:
            existing_pet = await db.pets.find_one({
                "id": pet_id_from_request,
                "owner_email": user.get("email", "").lower()
            })
        
        if not existing_pet:
            existing_pet = await db.pets.find_one({
                "name": {"$regex": f"^{pet_name}$", "$options": "i"},
                "owner_email": user.get("email", "").lower()
            })
        
        pet_id = existing_pet.get("id") if existing_pet else f"pet-{uuid.uuid4().hex[:12]}"
        
        # CRITICAL: Merge existing answers with new ones (NEVER overwrite, only add)
        # This ensures questions are NEVER repeated - they're tracked and excluded
        existing_answers = existing_pet.get("doggy_soul_answers") or {} if existing_pet else {}
        merged_answers = {**existing_answers}
        
        for key, value in new_soul_answers.items():
            # Only add if not already answered (unless it's a skipped question being re-answered)
            if key not in merged_answers or (isinstance(merged_answers.get(key), dict) and merged_answers[key].get('skipped')):
                merged_answers[key] = value
            elif value and not (isinstance(value, dict) and value.get('skipped')):
                # Update if new value is not skipped
                merged_answers[key] = value
        
        # Build update document
        update = {
            "id": pet_id,
            "name": pet_name,
            "owner_email": user.get("email", "").lower(),
            "doggy_soul_answers": merged_answers,
            "soul_score": soul_score,
            "overall_score": soul_score,
            "breed": pet_data.get("breed") or data.get("breed", "") or (existing_pet.get("breed") if existing_pet else ""),
            "gender": pet_data.get("gender", "") or (existing_pet.get("gender") if existing_pet else ""),
            "birth_date": pet_data.get("birth_date", "") or (existing_pet.get("birth_date") if existing_pet else ""),
            "weight": pet_data.get("weight") or (existing_pet.get("weight") if existing_pet else None),
            "weight_unit": pet_data.get("weight_unit", "kg") or (existing_pet.get("weight_unit") if existing_pet else "kg"),
            "updated_at": datetime.now(timezone.utc).isoformat(),
            # Track which questions have been answered (for deduplication)
            "answered_question_ids": list(set(
                (existing_pet.get("answered_question_ids", []) if existing_pet else []) + 
                answered_question_ids + 
                [k for k, v in merged_answers.items() if v and not (isinstance(v, dict) and v.get('skipped'))]
            ))
        }
        
        # Extract key fields from answers into structured data for quick access
        if merged_answers.get("food_allergies"):
            allergies = merged_answers["food_allergies"]
            update.setdefault("health", {})["allergies"] = [allergies] if isinstance(allergies, str) else allergies
        if merged_answers.get("separation_anxiety"):
            update.setdefault("personality", {})["separation_anxiety"] = merged_answers["separation_anxiety"]
        if merged_answers.get("loud_sounds"):
            update.setdefault("personality", {})["noise_sensitivity"] = merged_answers["loud_sounds"]
        if merged_answers.get("handling_comfort"):
            update.setdefault("care", {})["handling_sensitivity"] = merged_answers["handling_comfort"]
        if merged_answers.get("general_nature") or merged_answers.get("temperament"):
            update.setdefault("personality", {})["temperament"] = merged_answers.get("general_nature") or merged_answers.get("temperament")
        if merged_answers.get("exercise_needs"):
            update.setdefault("care", {})["exercise_needs"] = merged_answers["exercise_needs"]
        
        # Upsert pet
        await db.pets.update_one({"id": pet_id}, {"$set": update}, upsert=True)
        
        # Link pet to user
        await db.users.update_one(
            {"email": user.get("email", "").lower()},
            {"$addToSet": {"pets": pet_id, "pet_ids": pet_id}}
        )
        
        logger.info(f"[SOUL BUILDER] Saved/merged {len(new_soul_answers)} answers for {pet_name} (total: {len(merged_answers)}, score: {soul_score}%)")
        
        return {
            "success": True,
            "pet_id": pet_id,
            "pet_name": pet_name,
            "answers_saved": len(new_soul_answers),
            "total_answers": len(merged_answers),
            "soul_score": soul_score,
            "answered_question_ids": update["answered_question_ids"]
        }
    except HTTPException:
        raise
    except Exception as e:
        logger.error(f"[SOUL BUILDER] Save error: {e}")
        raise HTTPException(status_code=500, detail=str(e))


# ==================== PET SOUL BACKFILL ====================

@api_router.post("/admin/backfill-pet-soul-answers")
async def backfill_pet_soul_answers(background_tasks: BackgroundTasks, admin: dict = Depends(verify_admin)):
    """
    Backfill doggy_soul_answers for existing pets that have basic data but empty soul answers.
    This ensures onboarding data is reflected in the Pet Soul score.
    """
    async def do_backfill():
        updated_count = 0
        pets_cursor = db.pets.find({})
        
        async for pet in pets_cursor:
            current_answers = pet.get("doggy_soul_answers") or {}
            new_answers = dict(current_answers)  # Start with existing answers
            updated = False
            
            # Map basic pet fields to soul answer keys (only if not already set)
            field_mappings = [
                ("name", "name"),
                ("breed", "breed"),
                ("gender", "gender"),
                ("date_of_birth", "dob"),
                ("dob", "dob"),
                ("gotcha_day", "gotcha_date"),
                ("is_neutered", "spayed_neutered"),
            ]
            
            for pet_field, soul_key in field_mappings:
                pet_value = pet.get(pet_field)
                if pet_value and soul_key not in new_answers:
                    if soul_key == "spayed_neutered":
                        new_answers[soul_key] = "Yes" if pet_value else "No"
                    else:
                        new_answers[soul_key] = pet_value
                    updated = True
            
            # Handle weight specially (combine with unit)
            if pet.get("weight") and "weight" not in new_answers:
                weight_unit = pet.get("weight_unit", "kg")
                new_answers["weight"] = f"{pet['weight']} {weight_unit}"
                updated = True
            
            # Update pet if we added new answers
            if updated and len(new_answers) > len(current_answers):
                await db.pets.update_one(
                    {"id": pet["id"]},
                    {"$set": {"doggy_soul_answers": new_answers}}
                )
                updated_count += 1
                logger.info(f"Backfilled soul answers for pet {pet.get('name')} ({pet['id']}): {len(new_answers)} total answers")
        
        logger.info(f"Pet Soul backfill complete: Updated {updated_count} pets")
    
    background_tasks.add_task(do_backfill)
    
    return {
        "success": True,
        "message": "Pet Soul backfill started in background. Check logs for progress."
    }


