@api_router.get("/admin/breed-products")
async def get_admin_breed_products(
    breed: Optional[str] = None,
    category: Optional[str] = None,
    pillar: Optional[str] = None,
    search: Optional[str] = None,
    has_mockup: Optional[str] = None,
    is_active: Optional[bool] = None,
    limit: int = 100,
    skip: int = 0
):
    """Get breed products for admin management (is_mockup=True by default — proper mockups only)"""
    query = {"is_mockup": True}   # Only show proper product mockups, not portrait-only
    if breed:
        # Normalize breed and create regex pattern for matching
        from breed_normalise import normalise_breed
        import re as _re
        normalised = normalise_breed(breed)
        breed_pattern = _re.sub(r'[ _]', '[_ ]', normalised)
        query["$or"] = [
            {"breed": {"$regex": breed_pattern, "$options": "i"}},
            {"breed": "all"},
        ]
    if category:
        query["category"] = {"$regex": category, "$options": "i"}
    if pillar:
        query["pillars"] = {"$in": [pillar.lower()]}
    if search:
        query["name"] = {"$regex": search, "$options": "i"}
    if has_mockup == "true":
        query["cloudinary_url"] = {"$exists": True, "$ne": None, "$ne": ""}
    elif has_mockup == "false":
        query["$or"] = [{"cloudinary_url": {"$exists": False}}, {"cloudinary_url": None}, {"cloudinary_url": ""}]
    if is_active is not None:
        query["is_active"] = is_active
    
    products = await db.breed_products.find(query, {"_id": 0}).skip(skip).limit(limit).to_list(limit)
    total = await db.breed_products.count_documents(query)
    
    return {"products": products, "total": total}

