@api_router.post("/admin/breed-products/import")
async def import_breed_products(request: dict):
    """Bulk import/upsert breed products from CSV rows.
    Matches by breed+product_type (natural key) to update pillar mappings.
    Admin can re-import CSV anytime to update pillars, categories, prices."""
    rows = request.get("rows", [])
    if not rows:
        raise HTTPException(status_code=400, detail="No rows provided")
    
    from pymongo import UpdateOne
    ops = []
    for row in rows:
        breed = (row.get("breed", "") or "").lower().strip()
        product_type = (row.get("product_type", "") or "").lower().strip()
        if not breed or not product_type:
            continue
        
        pillar = (row.get("pillar", "") or "").lower().strip()
        all_pillars_str = row.get("pillars", row.get("all_pillars", "")) or ""
        pillars = [p.strip().lower() for p in all_pillars_str.split("|") if p.strip()]
        if not pillars and pillar:
            pillars = [pillar]
        
        update_doc = {
            "breed": breed,
            "product_type": product_type,
            "pillar": pillar,
            "pillars": pillars,
            "updated_at": get_utc_timestamp(),
        }
        name = row.get("name", row.get("product_name", ""))
        if name:
            update_doc["name"] = name
        sub_cat = (row.get("sub_category", "") or "").strip()
        if sub_cat:
            update_doc["sub_category"] = sub_cat
        cat = (row.get("category", "") or "").strip()
        if cat:
            update_doc["category"] = cat
        price = float(row.get("price", 0) or 0)
        if price > 0:
            update_doc["price"] = price
        img = (row.get("cloudinary_url", "") or row.get("image_url", "") or "").strip()
        if img:
            update_doc["cloudinary_url"] = img
        
        # Match by breed + product_type (natural key for breed products)
        ops.append(UpdateOne(
            {"breed": breed, "product_type": product_type},
            {"$set": update_doc,
             "$setOnInsert": {
                 "id": f"bp-{breed}-{product_type}",
                 "is_active": True, "active": True,
                 "is_mockup": True,
                 "created_at": get_utc_timestamp(),
             }},
            upsert=True
        ))
    
    if not ops:
        return {"success": False, "error": "No valid rows found"}
    
    result = await db.breed_products.bulk_write(ops, ordered=False)
    return {
        "success": True,
        "inserted": result.upserted_count,
        "updated": result.modified_count,
        "total": len(ops)
    }


@api_router.post("/admin/breed-products/seed-type")
async def seed_new_product_type(request: dict):
    """Seed a new product type across selected breeds and pillars"""
    product_type  = request.get("product_type", "").lower().strip()
    name_template = request.get("name_template", "{breed} {product_type}")
    price         = float(request.get("price", 0) or 0)
    pillars       = request.get("pillars", [])
    breeds_param  = request.get("breeds", "all")  # "all" or list of breed strings
    description   = request.get("description", "")
    
    if not product_type:
        raise HTTPException(status_code=400, detail="product_type is required")
    if not pillars:
        raise HTTPException(status_code=400, detail="At least one pillar is required")
    
    # Get breeds
    if breeds_param == "all" or not breeds_param:
        breed_docs = await db.breed_products.distinct("breed")
        breeds = [b for b in breed_docs if b and b != "all"]
    else:
        breeds = breeds_param if isinstance(breeds_param, list) else [breeds_param]
    
    from pymongo import UpdateOne
    ops = []
    created = []
    for breed in breeds:
        product_id = f"bp-{breed}-{product_type}-{'_'.join(pillars)}"
        display_name = name_template.replace("{breed}", breed.replace("_", " ").title()).replace("{product_type}", product_type.replace("_", " ").title())
        ops.append(UpdateOne(
            {"id": product_id},
            {"$setOnInsert": {
                "id": product_id,
                "breed": breed,
                "product_type": product_type,
                "name": display_name,
                "pillar": pillars[0],
                "pillars": pillars,
                "price": price,
                "description": description,
                "cloudinary_url": None,
                "mockup_url": None,
                "is_active": True,
                "active": True,
                "is_mockup": False,
                "created_at": get_utc_timestamp(),
                "updated_at": get_utc_timestamp(),
            }},
            upsert=True
        ))
        created.append({"breed": breed, "product_type": product_type, "name": display_name})
    
    result = await db.breed_products.bulk_write(ops, ordered=False)
    return {
        "success": True,
        "seeded": result.upserted_count,
        "already_existed": result.matched_count,
        "total_breeds": len(breeds),
        "products": created[:10]
    }


@api_router.patch("/admin/products/{product_id}/toggle-active")
async def toggle_product_active(product_id: str):
    """Toggle is_active status for a product in products_master.
    NOTE: This only changes is_active flag — does NOT change visibility.status.
    Use DELETE /api/product-box/products/{id} to archive (hide from admin list)."""
    product = await db.products_master.find_one(
        {"$or": [{"id": product_id}, {"shopify_id": product_id}]}
    )
    if not product:
        raise HTTPException(status_code=404, detail="Product not found")
    
    new_status = not product.get("is_active", True)
    # When re-activating, also restore visibility.status (un-archive if needed)
    # When deactivating, only change is_active — do NOT archive (archive is a separate action)
    update_fields = {
        "is_active": new_status,
        "active": new_status,
        "updated_at": get_utc_timestamp()
    }
    if new_status:
        update_fields["visibility.status"] = "active"
        update_fields["visibility.is_active"] = True
    else:
        update_fields["visibility.status"] = "inactive"
        update_fields["visibility.is_active"] = False
    
    await db.products_master.update_one(
        {"$or": [{"id": product_id}, {"shopify_id": product_id}]},
        {"$set": update_fields}
    )
    
    return {"success": True, "is_active": new_status}


@api_router.post("/admin/products/import-csv")
async def import_products_csv(
    request: ProductCSVImportRequest,
    credentials: HTTPBasicCredentials = Depends(security)
):
    """Import products from CSV data"""
    verify_admin(credentials)
    
    imported = 0
    updated = 0
    errors = []
    
    for product_data in request.products:
        try:
            # Check if product exists by name
            existing = await db.products_master.find_one({"name": product_data.get("name")})
            
            product_doc = {
                "name": product_data.get("name", ""),
                "description": product_data.get("description", ""),
                "category": product_data.get("category", "other"),
                "price": float(product_data.get("price", 0)),
                "image": product_data.get("image", ""),
                "status": product_data.get("status", "active"),
                "available": product_data.get("available", True),
                "tags": product_data.get("tags", []),
                "updated_at": get_utc_timestamp()
            }
            
            if product_data.get("original_price"):
                product_doc["original_price"] = float(product_data["original_price"])
            
            if existing:
                # Update existing product
                await db.products_master.update_one(
                    {"_id": existing["_id"]},
                    {"$set": product_doc}
                )
                updated += 1
            else:
                # Create new product
                product_doc["id"] = f"csv-{uuid.uuid4().hex[:12]}"
                product_doc["created_at"] = get_utc_timestamp()
                await db.products_master.insert_one(product_doc)
                imported += 1
                
        except Exception as e:
            errors.append(f"Error with '{product_data.get('name', 'Unknown')}': {str(e)}")
    
    return {
        "imported": imported,
        "updated": updated,
        "errors": errors[:10] if errors else []
    }


@api_router.get("/admin/export/products-csv")
async def export_products_csv(
    credentials: HTTPBasicCredentials = Depends(security)
):
    """Export all products as CSV file"""
    verify_admin(credentials)
    
    products = await db.products_master.find({}, {"_id": 0}).to_list(10000)
    
    # Create CSV content
    output = io.StringIO()
    if products:
        # Get all unique keys across all products
        all_keys = set()
        for p in products:
            all_keys.update(p.keys())
        
        # Priority columns first
        priority_cols = ['id', 'name', 'description', 'price', 'pillar', 'category', 'tags', 'image']
        fieldnames = [c for c in priority_cols if c in all_keys]
        fieldnames.extend([k for k in sorted(all_keys) if k not in fieldnames])
        
        writer = csv.DictWriter(output, fieldnames=fieldnames)
        writer.writeheader()
        
        for product in products:
            row = {}
            for key in fieldnames:
                value = product.get(key, '')
                # Convert lists/dicts to JSON string
                if isinstance(value, (list, dict)):
                    row[key] = json.dumps(value)
                else:
                    row[key] = value
            writer.writerow(row)
    
    # Return as CSV file
    from fastapi.responses import StreamingResponse
    output.seek(0)
    return StreamingResponse(
        iter([output.getvalue()]),
        media_type="text/csv",
        headers={"Content-Disposition": "attachment; filename=products_export.csv"}
    )


