@api_router.post("/pets")
async def create_pet_profile(pet: PetProfileCreate, current_user: dict = Depends(get_current_user)):
    """Create a new pet profile linked to the authenticated user"""
    pet_id = f"pet-{uuid.uuid4().hex[:12]}"
    pet_pass_number = await generate_pet_pass_number_server()
    now = get_utc_timestamp()
    
    pet_data = {
        "id": pet_id,
        "pet_pass_number": pet_pass_number,
        **pet.model_dump(),
        "owner_email": current_user["email"],  # Link to authenticated user
        "achievements": [],
        "order_history": [],
        "created_at": now,
        "updated_at": now
    }
    
    # Auto-add birthday and gotcha day to celebrations if dates provided
    celebrations = list(pet.celebrations) if pet.celebrations else []
    
    if pet.birth_date and not any(c.occasion == "birthday" for c in celebrations):
        celebrations.append(PetCelebration(
            occasion="birthday",
            date=pet.birth_date,
            is_recurring=True
        ))
    
    if pet.gotcha_date and not any(c.occasion == "gotcha_day" for c in celebrations):
        celebrations.append(PetCelebration(
            occasion="gotcha_day",
            date=pet.gotcha_date,
            is_recurring=True
        ))
    
    pet_data["celebrations"] = [c.model_dump() for c in celebrations]
    
    await db.pets.insert_one(pet_data)
    
    # Remove MongoDB _id before returning
    pet_data.pop("_id", None)
    
    # Auto-create ticket for Command Center
    try:
        from ticket_auto_creation import on_pet_added
        await on_pet_added(pet_data, current_user)
    except Exception as e:
        logger.error(f"Auto-ticket for pet addition failed: {e}")
    
    logger.info(f"Created pet profile: {pet_id} - {pet.name}")

    # Send pawrent welcome if puppy (< 6 months old)
    try:
        if pet.birth_date:
            from datetime import date as dt_date
            today = dt_date.today()
            bday = None
            try:
                from datetime import datetime as _dt
                bday = _dt.fromisoformat(str(pet.birth_date)).date()
            except Exception:
                pass
            if bday and (today - bday).days < 183:  # < 6 months
                import asyncio
                from services.whatsapp_service import send_pawrent_welcome
                asyncio.ensure_future(
                    send_pawrent_welcome(current_user, pet_data)
                )
    except Exception as _pw_err:
        logger.warning(f"Pawrent welcome notification failed: {_pw_err}")

    return {"message": "Pet profile created", "pet": pet_data}


@api_router.get("/pets")
@api_router.get("/pets/my-pets")
async def get_my_pets(current_user: dict = Depends(get_current_user)):
    """Get pets for the logged-in user"""
    from bson import ObjectId
    
    def sanitize_objectids(obj):
        """Recursively convert ObjectId to string"""
        if isinstance(obj, ObjectId):
            return str(obj)
        elif isinstance(obj, dict):
            return {k: sanitize_objectids(v) for k, v in obj.items()}
        elif isinstance(obj, list):
            return [sanitize_objectids(item) for item in obj]
        return obj
    
    pets_raw = await db.pets.find({"owner_email": current_user["email"]}, {"_id": 0}).to_list(50)
    pets = [sanitize_objectids(p) for p in pets_raw]
    
    for pet in pets:
        stored_score = pet.get("overall_score", 0) or 0
        answers = pet.get("doggy_soul_answers") or pet.get("soul_answers") or {}

        # Fast path: use stored score if already calculated (skip CPU-intensive recalc)
        if stored_score > 0:
            pet["overall_score"] = stored_score
            pet["score_tier"] = pet.get("score_tier", "explorer")
        elif answers:
            # Only recalculate if no stored score
            score_data = calculate_pet_soul_score(answers)
            pet["overall_score"] = score_data["total_score"]
            pet["score_tier"] = score_data["tier"]["key"] if score_data["tier"] else "newcomer"
        else:
            pet["overall_score"] = 0
            pet["score_tier"] = "newcomer"
    
    return {"pets": pets}


