async def list_pet_profiles(
    owner_email: Optional[str] = None,
    owner_phone: Optional[str] = None,
    limit: int = 50,
    skip: int = 0
):
    """List pet profiles, filtered by owner"""
    if not (owner_email or owner_phone):
        raise HTTPException(
            status_code=400, 
            detail="To protect pet privacy, you must provide an owner_email or owner_phone to view profiles."
        )
    
    query = {}
    if owner_email:
        query["owner_email"] = owner_email
    if owner_phone:
        query["owner_phone"] = owner_phone
    
    pets = await db.pets.find(query, {"_id": 0}).skip(skip).limit(limit).to_list(limit)
    total = await db.pets.count_documents(query)
    
    return {"pets": pets, "total": total}


@api_router.get("/pets/{pet_id}")
async def get_pet_profile(pet_id: str):
    """Get a specific pet profile"""
    from bson import ObjectId
    
    def sanitize_objectids(obj):
        """Recursively convert ObjectId to string"""
        if isinstance(obj, ObjectId):
            return str(obj)
        elif isinstance(obj, dict):
            return {k: sanitize_objectids(v) for k, v in obj.items()}
        elif isinstance(obj, list):
            return [sanitize_objectids(item) for item in obj]
        return obj
    
    pet = await db.pets.find_one({"id": pet_id}, {"_id": 0})
    if not pet:
        raise HTTPException(status_code=404, detail="Pet not found")
    return sanitize_objectids(pet)



@api_router.get("/pets/{pet_id}/soul")
async def get_pet_soul(pet_id: str):
    """Get pet soul score, answers and chapter progress."""
    pet = await db.pets.find_one({"id": pet_id}, {"_id": 0,
        "id": 1, "name": 1, "breed": 1, "overall_score": 1,
        "doggy_soul_answers": 1, "doggy_soul_meta": 1})
    if not pet:
        raise HTTPException(status_code=404, detail="Pet not found")
    answers = pet.get("doggy_soul_answers") or {}
    answered = len([v for v in answers.values() if v])
    return {
        "pet_id": pet_id,
        "name": pet.get("name"),
        "breed": pet.get("breed"),
        "overall_score": pet.get("overall_score", 0),
        "answered_count": answered,
        "total_questions": 51,
        "soul_percentage": min(round((answered / 51) * 100), 100),
        "chapters": {
            cat: round(data.get("percentage", 0))
            for cat, data in calculate_pet_soul_score(answers).get("category_scores", {}).items()
        }
    }



@api_router.put("/pets/{pet_id}")
async def update_pet_profile(pet_id: str, updates: PetProfileUpdate):
    """Update a pet profile"""
    pet = await db.pets.find_one({"id": pet_id})
    if not pet:
        raise HTTPException(status_code=404, detail="Pet not found")
    
    update_data = {k: v for k, v in updates.model_dump().items() if v is not None}
    update_data["updated_at"] = get_utc_timestamp()
    
    # Handle nested objects properly
    if "soul" in update_data and update_data["soul"]:
        update_data["soul"] = updates.soul.model_dump()
    if "preferences" in update_data and update_data["preferences"]:
        update_data["preferences"] = updates.preferences.model_dump()
    if "celebrations" in update_data and update_data["celebrations"]:
        update_data["celebrations"] = [c.model_dump() for c in updates.celebrations]
    
    await db.pets.update_one({"id": pet_id}, {"$set": update_data})
    
    # Create admin notification for pet profile update
    try:
        pet_name = pet.get("name", "Unknown Pet")
        owner_email = pet.get("owner_email", "Unknown")
        # Get owner info from members collection
        member = await db.members.find_one({"pets.id": pet_id})
        if member:
            owner_email = member.get("email", owner_email)
            owner_name = member.get("name", member.get("email", "Unknown"))
        else:
            owner_name = pet.get("owner_name", owner_email)
        
        # Determine what was updated
        updated_fields = list(update_data.keys())
        updated_fields = [f for f in updated_fields if f not in ['updated_at']]
        changes_summary = ", ".join(updated_fields[:3])
        if len(updated_fields) > 3:
            changes_summary += f" +{len(updated_fields) - 3} more"
        
        notification = {
            "id": f"notif-{uuid.uuid4().hex[:12]}",
            "type": "pet_profile_updated",
            "title": f"🐕 {pet_name}'s profile updated",
            "message": f"{owner_name} updated {pet_name}'s profile: {changes_summary}",
            "pet_id": pet_id,
            "pet_name": pet_name,
            "owner_email": owner_email,
            "changes": updated_fields,
            "read": False,
            "created_at": get_utc_timestamp()
        }
        await db.admin_notifications.insert_one(notification)
        logger.info(f"Admin notification created for pet update: {pet_name} by {owner_name}")
    except Exception as e:
        logger.error(f"Failed to create admin notification: {e}")
        # Don't fail the request if notification fails
    
    updated_pet = await db.pets.find_one({"id": pet_id}, {"_id": 0})
    return {"message": "Pet profile updated", "pet": updated_pet}


@api_router.delete("/pets/{pet_id}")
async def delete_pet_profile(pet_id: str):
    """Delete a pet profile"""
    result = await db.pets.delete_one({"id": pet_id})
    if result.deleted_count == 0:
        raise HTTPException(status_code=404, detail="Pet not found")
    return {"message": "Pet profile deleted"}


