async def create_admin_notification(
    notification_type: str,
    title: str,
    message: str,
    category: str = "general",
    related_id: str = None,
    link_to: str = None,
    priority: str = "normal",
    metadata: dict = None
):
    """
    Create a notification for admin dashboard
    
    Types: order, reservation, meetup, chat, review, member, stock, ticket, system
    Categories: celebrate, dine, stay, care, travel, general
    Priority: low, normal, high, urgent
    """
    safe_category = category or (metadata or {}).get("pillar") or (metadata or {}).get("type") or "general"
    notification = {
        "id": f"notif-{uuid.uuid4().hex[:12]}",
        "type": notification_type,
        "title": title,
        "message": message,
        "category": safe_category,
        "related_id": related_id,
        "link_to": link_to,  # e.g., "/admin?tab=orders" or "/admin?tab=dine&subtab=reservations"
        "priority": priority,
        "metadata": metadata or {},
        "read": False,
        "created_at": get_utc_timestamp()
    }
    
    await db.admin_notifications.insert_one(notification)
    logger.info(f"Admin notification created: {notification_type} - {title}")
    return notification["id"]


@api_router.get("/admin/notifications")
async def get_admin_notifications(
    limit: int = 50,
    unread_only: bool = False,
    category: str = None,
    credentials: HTTPBasicCredentials = Depends(security)
):
    """Get admin notifications"""
    verify_admin(credentials)
    
    query = {}
    if unread_only:
        query["read"] = False
    if category:
        query["category"] = category
    
    # Use aggregation to handle mixed date formats
    pipeline = [
        {"$match": query},
        {"$addFields": {
            "sort_date": {
                "$dateFromString": {
                    "dateString": "$created_at",
                    "onError": {"$toDate": "$created_at"},
                    "onNull": {"$toDate": "1970-01-01"}
                }
            }
        }},
        {"$sort": {"sort_date": -1}},
        {"$limit": limit},
        {"$project": {"_id": 0, "sort_date": 0}}
    ]
    
    notifications = await db.admin_notifications.aggregate(pipeline).to_list(limit)

    # ── Normalize fields: ensure title + message always present ──────────
    for n in notifications:
        # title: use subject, title, or generate from type + pet_name
        if not n.get("title"):
            if n.get("subject"):
                n["title"] = n["subject"]
            else:
                intent = (n.get("type") or "request").replace("_", " ").title()
                pet = n.get("pet_name") or n.get("petName") or ""
                n["title"] = f"{intent} — {pet}" if pet else intent
        # message: use message, pet context, or fallback
        if not n.get("message"):
            pet = n.get("pet_name") or n.get("petName") or ""
            pillar = n.get("pillar") or n.get("category") or ""
            parent = n.get("parent_id") or n.get("parent_email") or ""
            n["message"] = (
                f"{pet}'s parent via {pillar}" if pet and pillar
                else pet or parent or "New request received"
            )
        # type: fall back to intent_primary if type missing
        if not n.get("type") and n.get("intent_primary"):
            n["type"] = n["intent_primary"]
        if not n.get("category"):
            n["category"] = n.get("pillar") or n.get("type") or "general"

    # Get unread count
    unread_count = await db.admin_notifications.count_documents({"read": False})
    
    # Get counts by category
    category_pipeline = [
        {"$match": {"read": False}},
        {"$group": {"_id": "$category", "count": {"$sum": 1}}}
    ]
    category_counts = {}
    async for doc in db.admin_notifications.aggregate(category_pipeline):
        key = doc.get("_id") or "general"
        category_counts[key] = category_counts.get(key, 0) + doc["count"]
    
    return {
        "notifications": notifications,
        "unread_count": unread_count,
        "category_counts": category_counts
    }


