@api_router.post("/admin/products/{product_id}/regenerate-image")
async def regenerate_single_product_image(
    product_id: str,
    background_tasks: BackgroundTasks,
    username: str = Depends(verify_admin_auth),
):
    """Regenerate AI image for a single product (background)."""
    product = await db.products_master.find_one({"id": product_id}, {"_id": 0})
    if not product:
        raise HTTPException(status_code=404, detail="Product not found")

    async def _regen():
        from ai_image_service import generate_ai_image
        prompt = product.get("ai_image_prompt") or \
            f"Premium dog product, {product['name']}, clean white background, professional product photography"
        url = await generate_ai_image(prompt)
        if url:
            await db.products_master.update_one(
                {"id": product_id},
                {"$set": {
                    "watercolor_image": url, "cloudinary_url": url,
                    "image_url": url, "image": url, "images": [url],
                    "ai_image_generated": True, "locally_edited": True,
                    "image_updated_at": datetime.now(timezone.utc).isoformat(),
                }}
            )
    background_tasks.add_task(_regen)
    return {"message": f"Image regeneration started for {product['name']}", "product_id": product_id}


@api_router.post("/admin/products/{product_id}/generate-image")
async def generate_product_image_async(
    product_id: str,
    background_tasks: BackgroundTasks,
    username: str = Depends(verify_admin_auth),
):
    """Start AI image generation for a single product as a background task.
    Returns immediately. Poll /admin/products/{id}/image-status for result."""
    product = await db.products_master.find_one({"id": product_id}, {"_id": 0})
    if not product:
        raise HTTPException(status_code=404, detail="Product not found")

    # Mark as in-progress
    _single_image_jobs[product_id] = {"status": "generating", "product_id": product_id, "started_at": datetime.now(timezone.utc).isoformat()}

    background_tasks.add_task(_run_single_product_image, product_id, product)
    return {"status": "generating", "product_id": product_id, "poll_url": f"/api/admin/products/{product_id}/image-status"}


@api_router.get("/admin/products/{product_id}/image-status")
async def get_product_image_status(
    product_id: str,
    username: str = Depends(verify_admin_auth),
):
    """Poll for the result of a background image generation job."""
    job = _single_image_jobs.get(product_id)
    if not job:
        # Check if product already has a cloudinary image (completed in previous run)
        product = await db.products_master.find_one({"id": product_id}, {"_id": 0, "image_url": 1})
        if product and product.get("image_url", "").startswith("https://res.cloudinary.com"):
            return {"status": "complete", "image_url": product["image_url"], "product_id": product_id}
        return {"status": "not_started", "product_id": product_id}
    return job


@api_router.post("/admin/generate-image")
async def generate_image_universal(
    data: dict,
    username: str = Depends(verify_admin_auth),
):
    """Universal AI image generator. Pass prompt + optional entity_type/entity_id to auto-save result.
    entity_type: 'product' | 'service' | 'bundle' | 'breed_product'
    Returns {url, success}"""
    from ai_image_service import generate_ai_image

    prompt = data.get("prompt", "").strip()
    entity_type = data.get("entity_type", "")
    entity_id = data.get("entity_id", "")
    save_prompt_flag = data.get("save_prompt", False)

    if not prompt:
        raise HTTPException(status_code=400, detail="prompt is required")

    url = await generate_ai_image(prompt)
    if not url:
        raise HTTPException(status_code=500, detail="Image generation failed — check AI service")

    # Save result to the entity if entity info provided
    if entity_type and entity_id:
        # Normalize entity_type aliases — soul_made / soul_product → check breed_products first, then products_master
        soul_aliases = {"soul_made", "soul_product", "breed_product"}
        collection_map = {
            "product": db.products_master,
            "service": db.services_master,
            "bundle": db.bundles,
            "breed_product": db.breed_products,
        }
        col = collection_map.get(entity_type)

        # For soul_made aliases not in map, probe breed_products then products_master
        if col is None and entity_type in soul_aliases:
            if await db.breed_products.find_one({"id": entity_id}):
                col = db.breed_products
            else:
                col = db.products_master  # fallback — breed-* IDs that live in products_master

        if col is not None:
            update_fields = {
                "ai_image_prompt": prompt,
                "ai_prompt": prompt,
                "watercolor_image": url,  # highest priority in getProductImage — ALWAYS set
                "cloudinary_url": url,
                "image_url": url,
                "image": url,
                "ai_image_generated": True,
                "locally_edited": True,
                "image_updated_at": datetime.now(timezone.utc).isoformat(),
            }
            await col.update_one(
                {"$or": [{"id": entity_id}, {"_id": entity_id}]},
                {"$set": update_fields}
            )

    return {"url": url, "success": True}


@api_router.post("/admin/sync-image-fields")
async def sync_image_fields(username: str = Depends(verify_admin_auth)):
    """Sync cloudinary_url → watercolor_image for breed_products, and cloudinary_url → image_url for products_master.
    Run this after bulk image uploads to ensure all product cards read the correct image field."""
    results = {}

    # 1. breed_products: cloudinary_url → watercolor_image + image_url
    bp_result = await db.breed_products.update_many(
        {"cloudinary_url": {"$exists": True, "$ne": ""}},
        [{"$set": {"watercolor_image": "$cloudinary_url", "image_url": "$cloudinary_url"}}]
    )
    results["breed_products_synced"] = bp_result.modified_count

    # 2. products_master: cloudinary_url → image_url (don't overwrite watercolor_image)
    pm_result = await db.products_master.update_many(
        {"cloudinary_url": {"$exists": True, "$ne": ""}},
        [{"$set": {"image_url": "$cloudinary_url"}}]
    )
    results["products_master_synced"] = pm_result.modified_count

    return {"success": True, "synced": results}


@api_router.post("/admin/cleanup-broken-images")
async def cleanup_broken_images(username: str = Depends(verify_admin_auth)):
    """Remove broken emergentagent.com staging URLs from image fields in all collections."""
    results = {}

    # 1. products_master — unset `image` field with broken staging URLs
    r1 = await db.products_master.update_many(
        {"image": {"$regex": "emergentagent.com", "$options": "i"}},
        {"$unset": {"image": ""}}
    )
    results["products_master_image_cleaned"] = r1.modified_count

    # 2. products_master — pull broken URLs from images[] array
    r2 = await db.products_master.update_many(
        {"images": {"$elemMatch": {"$regex": "emergentagent.com", "$options": "i"}}},
        {"$pull": {"images": {"$regex": "emergentagent.com", "$options": "i"}}}
    )
    results["products_master_images_array_cleaned"] = r2.modified_count

    # 3. breed_products — clean image field
    r3 = await db.breed_products.update_many(
        {"image": {"$regex": "emergentagent.com", "$options": "i"}},
        {"$unset": {"image": ""}}
    )
    results["breed_products_image_cleaned"] = r3.modified_count

    # 4. bundles
    r4 = await db.bundles.update_many(
        {"image": {"$regex": "emergentagent.com", "$options": "i"}},
        {"$unset": {"image": ""}}
    )
    results["bundles_image_cleaned"] = r4.modified_count

    return {"success": True, "cleaned": results}



async def generate_bundle_image_sync(
    bundle_id: str,
    username: str = Depends(verify_admin_auth),
):
    """Generate AI image for a celebrate bundle — synchronous, returns URL immediately."""
    import os
    import base64
    import cloudinary
    import cloudinary.uploader
    from emergentintegrations.llm.openai.image_generation import OpenAIImageGeneration

    bundle = await db.celebrate_bundles.find_one(
        {"$or": [{"id": bundle_id}, {"_id": bundle_id}]}, {"_id": 0}
    )
    if not bundle:
        raise HTTPException(status_code=404, detail="Bundle not found")

    emergent_api_key = (
        os.environ.get("EMERGENT_LLM_KEY")
        or os.environ.get("EMERGENT_API_KEY")
        or os.environ.get("EMERGENT_MODEL_API_KEY")
    )
    if not emergent_api_key:
        raise HTTPException(status_code=500, detail="Image generation API key not configured")

    if not os.environ.get("CLOUDINARY_CLOUD_NAME"):
        raise HTTPException(status_code=500, detail="Cloudinary not configured")
    cloudinary.config(
        cloud_name=os.environ.get("CLOUDINARY_CLOUD_NAME"),
        api_key=os.environ.get("CLOUDINARY_API_KEY"),
        api_secret=os.environ.get("CLOUDINARY_API_SECRET"),
    )

    bundle_name = bundle.get("name", "Birthday Bundle")
    items = bundle.get("items", "")
    prompt = (
        f"Soulful watercolor illustration of a dog birthday gift bundle called '{bundle_name}', "
        f"containing {items[:80] if items else 'birthday treats, toys and accessories'}, "
        "beautifully arranged, warm painterly brushstrokes, soft layered watercolor pigments, "
        "premium editorial composition, elegant and emotive, white background, "
        "professional illustration style, similar to premium pet brand art"
    )

    try:
        image_gen = OpenAIImageGeneration(api_key=emergent_api_key)
        images = await image_gen.generate_images(prompt=prompt, number_of_images=1, model="gpt-image-1")
        if not images:
            raise HTTPException(status_code=500, detail="Image generation returned no results")

        img_b64 = base64.b64encode(images[0]).decode("utf-8")
        upload_result = cloudinary.uploader.upload(
            f"data:image/png;base64,{img_b64}",
            folder="bundles/ai-generated",
            public_id=f"bundle-{bundle_id}",
            overwrite=True,
            resource_type="image",
        )
        image_url = upload_result.get("secure_url")
        if not image_url:
            raise HTTPException(status_code=500, detail="Cloudinary upload failed")

        await db.celebrate_bundles.update_one(
            {"$or": [{"id": bundle_id}, {"_id": bundle_id}]},
            {"$set": {"image": image_url, "image_url": image_url}}
        )
        return {"success": True, "image_url": image_url, "bundle_id": bundle_id}
    except Exception as e:
        logger.error(f"Bundle image generation failed for {bundle_id}: {e}")
        raise HTTPException(status_code=500, detail=f"Image generation failed: {str(e)}")


@api_router.post("/admin/bundles/{bundle_id}/generate-image")
async def generate_generic_bundle_image(
    bundle_id: str,
    request: Request,
    username: str = Depends(verify_admin_auth),
):
    """Generate AI watercolor image for any bundle in the bundles collection."""
    import os
    import base64
    import cloudinary
    import cloudinary.uploader
    from emergentintegrations.llm.openai.image_generation import OpenAIImageGeneration

    bundle = await db.bundles.find_one(
        {"$or": [{"id": bundle_id}, {"_id": bundle_id}]}, {"_id": 0}
    )
    if not bundle:
        raise HTTPException(status_code=404, detail="Bundle not found")

    emergent_api_key = (
        os.environ.get("EMERGENT_LLM_KEY")
        or os.environ.get("EMERGENT_API_KEY")
        or os.environ.get("EMERGENT_MODEL_API_KEY")
    )
    if not emergent_api_key:
        raise HTTPException(status_code=500, detail="Image generation API key not configured")

    if not os.environ.get("CLOUDINARY_CLOUD_NAME"):
        raise HTTPException(status_code=500, detail="Cloudinary not configured")
    cloudinary.config(
        cloud_name=os.environ.get("CLOUDINARY_CLOUD_NAME"),
        api_key=os.environ.get("CLOUDINARY_API_KEY"),
        api_secret=os.environ.get("CLOUDINARY_API_SECRET"),
    )

    bundle_name = bundle.get("name", "Play Bundle")
    pillar = bundle.get("pillar", "play")
    items = bundle.get("items", "")
    try:
        req_body = await request.json()
        custom_prompt = req_body.get("prompt", "")
    except Exception:
        custom_prompt = ""
    prompt = custom_prompt if custom_prompt else (
        f"Soulful watercolor illustration of a dog {pillar} bundle called '{bundle_name}', "
        f"containing {items[:80] if items else 'toys, accessories, and treats'}, "
        "beautifully arranged, warm painterly brushstrokes, soft layered watercolor pigments, "
        "premium editorial composition, elegant and emotive, white background, "
        "professional illustration style, similar to premium pet brand art"
    )

    try:
        image_gen = OpenAIImageGeneration(api_key=emergent_api_key)
        images = await image_gen.generate_images(prompt=prompt, number_of_images=1, model="gpt-image-1")
        if not images:
            raise HTTPException(status_code=500, detail="Image generation returned no results")

        img_b64 = base64.b64encode(images[0]).decode("utf-8")
        upload_result = cloudinary.uploader.upload(
            f"data:image/png;base64,{img_b64}",
            folder="bundles/ai-generated",
            public_id=f"bundle-{bundle_id}-watercolor",
            overwrite=True,
            resource_type="image",
        )
        image_url = upload_result.get("secure_url")
        if not image_url:
            raise HTTPException(status_code=500, detail="Cloudinary upload failed")

        await db.bundles.update_one(
            {"$or": [{"id": bundle_id}, {"_id": bundle_id}]},
            {"$set": {"image_url": image_url, "watercolor_image": image_url}}
        )
        return {"success": True, "image_url": image_url, "bundle_id": bundle_id}
    except Exception as e:
        logger.error(f"Generic bundle image generation failed for {bundle_id}: {e}")

# ── CAKE ORDERS ────────────────────────────────────────────────────────────────

@api_router.post("/celebrate/cake-order")
async def submit_cake_order(order: dict, current_user: dict = Depends(get_current_user)):
    """Receives full cake order from DoggyBakeryCakeModal. Saves to cake_orders + service desk ticket + admin notification."""
    from datetime import datetime, timezone
    import secrets as _secrets

    pet_id   = order.get("pet_id", "")
    pet_name = order.get("pet_name", "your dog")
    ts       = datetime.now(timezone.utc)
    order_id  = f"cake-{ts.strftime('%Y%m%d%H%M%S')}-{str(pet_id)[:8] if pet_id else 'guest'}"
    ticket_id = f"TDB-{ts.strftime('%Y%m%d-%H%M')}-{_secrets.token_hex(2).upper()}"

    cake_order = {
        "id": order_id,
        "user_id": str(current_user.get("_id", "")),
        "user_email": current_user.get("email", ""),
        "pet_id": pet_id,
        "pet_name": pet_name,
        "pet_breed": order.get("pet_breed", ""),
        "pet_allergies": order.get("pet_allergies", []),
        "product_name": order.get("product_name", ""),
        "product_id": order.get("product_id", ""),
        "product_image": order.get("product_image", ""),
        "product_price": order.get("product_price", 0),
        "flavour": order.get("flavour", ""),
        "base": order.get("base", ""),
        "size": order.get("size", ""),
        "shape": order.get("shape", ""),
        "pet_name_on_cake": order.get("pet_name_on_cake", pet_name),
        "message_on_cake": order.get("message_on_cake", ""),
        "delivery_date": order.get("delivery_date", ""),
        "delivery_time": order.get("delivery_time", ""),
        "delivery_type": order.get("delivery_type", "Delivery"),
        "total_price": order.get("total_price", 0),
        "life_vision": order.get("life_vision", ""),
        "status": "pending",
        "created_at": ts.isoformat(),
        "source": order.get("source", "doggy_bakery_cake_modal"),
    }
    await db.cake_orders.insert_one(cake_order)

    allergies_str = ", ".join(cake_order["pet_allergies"]) if cake_order["pet_allergies"] else "None"
    price_str = "\u20b9" + str(int(cake_order["total_price"])) if cake_order["total_price"] else "Price on request"
    life_vision_str = cake_order.get("life_vision", "")
    ticket_text = (
        "\U0001f382 CAKE ORDER \u2014 " + pet_name + "\n\n"
        "Product: " + (cake_order["product_name"] or "—") + "\n"
        "Flavour: " + (cake_order["flavour"] or "—") + "\n"
        "Base: " + (cake_order["base"] or "—") + "\n"
        "Size: " + (cake_order["size"] or "—") + "\n"
        "Shape: " + (cake_order["shape"] or "—") + "\n"
        "Name on cake: " + (cake_order["pet_name_on_cake"] or "—") + "\n"
        "Message: " + (cake_order["message_on_cake"] or "None") + "\n"
        "Delivery date: " + (cake_order["delivery_date"] or "—") + "\n"
        "Delivery time: " + (cake_order["delivery_time"] or "—") + "\n"
        "Delivery type: " + (cake_order["delivery_type"] or "—") + "\n"
        "Total: " + price_str + "\n\n"
        "Pet: " + pet_name + " (" + (cake_order["pet_breed"] or "Unknown") + ")\n"
        "Allergies: " + allergies_str + "\n"
        + ("North Star: \"" + life_vision_str + "\"\n" if life_vision_str else "")
        + "Customer: " + current_user.get("email", "")
    )

    ticket = {
        "id": ticket_id,
        "parent_id": current_user.get("email", "guest"),
        "pet_id": pet_id,
        "pillar": "celebrate",
        "intent_primary": "cake_order",
        "urgency": "normal",
        "status": "open",
        "channel": "doggy_bakery_cake_modal",
        "cake_order_id": order_id,
        "initial_message": {"sender": "parent", "text": ticket_text},
        "created_at": ts.isoformat(),
    }
    await db.service_desk_tickets.insert_one(ticket)

    await db.admin_notifications.insert_one({
        "id": f"NOTIF-{_secrets.token_hex(4).upper()}",
        "type": "cake_order",
        "title": "\U0001f382 New cake order \u2014 " + pet_name,
        "message": cake_order["flavour"] + " " + cake_order["shape"] + " cake for " + pet_name + " \u00b7 \u20b9" + str(cake_order["total_price"]) + " \u00b7 " + cake_order["delivery_date"],
        "ticket_id": ticket_id,
        "cake_order_id": order_id,
        "read": False,
        "created_at": ts.isoformat(),
    })

    return {
        "success": True,
        "cake_order_id": order_id,
        "ticket_id": ticket_id,
        "message": "Cake order placed for " + pet_name + ". Concierge\u00ae will confirm within 2 hours.",
    }


@api_router.get("/admin/cake-orders")
async def get_cake_orders(
    status: Optional[str] = None,
    date: Optional[str] = None,
    limit: int = 50,
    skip: int = 0,
    username: str = Depends(verify_admin),
):
    """Get all cake orders for admin view."""
    query: dict = {}
    if status:
        query["status"] = status
    if date:
        query["delivery_date"] = date

    orders = await db.cake_orders.find(query, {"_id": 0}).sort("created_at", -1).skip(skip).limit(limit).to_list(limit)
    total   = await db.cake_orders.count_documents(query)

    return {
        "orders": orders,
        "total": total,
        "pending":   await db.cake_orders.count_documents({"status": "pending"}),
        "confirmed": await db.cake_orders.count_documents({"status": "confirmed"}),
        "delivered": await db.cake_orders.count_documents({"status": "delivered"}),
    }


@api_router.patch("/admin/cake-orders/{order_id}/status")
async def update_cake_order_status(
    order_id: str,
    update: dict,
    username: str = Depends(verify_admin),
):
    """Update cake order status: pending → confirmed → baking → out_for_delivery → delivered."""
    from datetime import datetime, timezone

    VALID = ["pending", "confirmed", "baking", "out_for_delivery", "delivered", "cancelled"]
    new_status = update.get("status")
    if new_status not in VALID:
        raise HTTPException(status_code=400, detail=f"Invalid status. Must be one of: {VALID}")

    result = await db.cake_orders.update_one(
        {"id": order_id},
        {"$set": {
            "status": new_status,
            "updated_at": datetime.now(timezone.utc).isoformat(),
            "updated_by": username,
        }},
    )
    if result.matched_count == 0:
        raise HTTPException(status_code=404, detail="Cake order not found")

    return {"success": True, "status": new_status}


