@app.on_event("startup")
async def startup_load_admin_credentials():
    """Load admin credentials from database on startup"""
    logger.info("Starting admin credentials load...")
    await load_admin_credentials_from_db()
    logger.info("Admin credentials load complete")
    
    # Auto-seed blog posts if none exist
    await auto_seed_blog_posts()
    
    # Auto-seed engagement data (stories, tips) if none exist
    await initialize_engagement_data()
    logger.info("Engagement data initialization complete")
    
    # Auto-seed Learn OS content if none exist
    await auto_seed_learn_content()
    logger.info("Learn OS content initialization complete")
    
    # Start retention scheduler (runs daily at 3 AM UTC)
    try:
        from retention_scheduler import start_scheduler
        start_scheduler(db)
        logger.info("Retention scheduler started - will run daily at 3 AM UTC")
    except Exception as e:
        logger.warning(f"Could not start retention scheduler: {e}")

    # Start automation scheduler (daily digest, birthday & medication reminders)
    try:
        from scheduled_automations import create_scheduler, set_automation_db
        set_automation_db(db)
        automation_scheduler = create_scheduler()
        automation_scheduler.start()
        logger.info("Automation scheduler started — daily digest 8 AM, birthday 7 AM, meds 9 AM IST")
    except Exception as e:
        logger.warning(f"Could not start automation scheduler: {e}")

